export type RawPage = { css: string; html: string };

export const homePage: RawPage = {
  "css": ":root{\r\n    --nav-h:69px; --navy:#0b1530; --navy-2:#091128; --card:rgba(255,255,255,.045); --cyan:#4fd6e6; --violet:#b18fd6; --blue:#7db4e0; --green:#64e6a2;\r\n    --ink:#eaf0ff; --muted:#9eb0d8; --line:rgba(255,255,255,.12); --section-line:rgba(255,255,255,.26);\r\n  }\r\n  *{box-sizing:border-box;margin:0;padding:0}\r\n  html{scroll-behavior:smooth;scroll-padding-top:var(--nav-h)}\r\n  html,body{max-width:100%;overflow-x:hidden}\r\n  body{font-family:'Geist',-apple-system,sans-serif;background:var(--navy);color:var(--ink);-webkit-font-smoothing:antialiased;padding-top:var(--nav-h)}\r\n  a{color:inherit;text-decoration:none}\r\n  .wrap{width:100%;max-width:1180px;margin:0 auto;padding:0 24px}\r\n  .grad-t{color:var(--cyan)}\r\n  .eyebrow{font-size:12px;letter-spacing:.32em;text-transform:uppercase;color:var(--cyan);font-weight:600;line-height:1.6;overflow-wrap:anywhere}\r\n  section{position:relative;border-top:1px solid var(--section-line)}\r\n  section[id], header[id], #services{scroll-margin-top:var(--nav-h)}\r\n  h2{font-family:'Geist';font-weight:800;font-size:40px;line-height:1.1;letter-spacing:0}\r\n  /* NAV */\r\n  nav.top{position:fixed;top:0;left:0;right:0;width:100%;z-index:500;backdrop-filter:blur(14px);background:rgba(11,21,48,.9);border-bottom:1px solid var(--section-line);box-shadow:0 14px 34px rgba(0,0,0,.18)}\r\n  nav.top .row{display:flex;align-items:center;justify-content:space-between;min-height:68px;gap:18px}\r\n  .brand{display:flex;align-items:center;gap:12px}\r\n  .brand img{width:38px;height:38px;border-radius:9px}\r\n  .brand b{font-family:'Geist';font-weight:800;letter-spacing:.04em;font-size:17px}\r\n  .navlinks{display:none;gap:18px;font-size:13px;color:var(--muted);align-items:center;white-space:nowrap}\r\n  .navlinks a:hover{color:var(--ink)}\r\n  .navlinks a.nav-spot{font-weight:700;color:var(--ink);letter-spacing:.02em}\r\n  .navlinks a.nav-spot-cloud{color:var(--green)}\r\n  .navlinks a.nav-spot-cloud:hover{color:#8af0ba}\r\n  .navlinks a.nav-spot-ia{color:var(--cyan)}\r\n  .navlinks a.nav-spot-ia:hover{color:#7ee8f4}\r\n  .navlinks a.nav-spot-contact{padding:7px 14px;border:1px solid rgba(79,214,230,.35);border-radius:999px;color:var(--cyan);font-weight:700}\r\n  .navlinks a.nav-spot-contact:hover{border-color:rgba(79,214,230,.6);color:#7ee8f4;background:rgba(79,214,230,.06)}\r\n  .btn{display:inline-flex;align-items:center;gap:9px;padding:11px 20px;border-radius:999px;font-weight:600;font-size:14px;transition:.2s;border:1px solid transparent;cursor:pointer}\r\n  .btn-primary{background:var(--cyan);color:#06122b;box-shadow:0 10px 24px rgba(79,214,230,.18)}\r\n  .btn-primary:hover{transform:translateY(-2px);box-shadow:0 14px 32px rgba(79,214,230,.24)}\r\n  .btn .btn-arrow{width:28px;height:16px;flex:none;margin-left:2px}\r\n  .btn-ghost{border-color:var(--line);color:var(--ink)}\r\n  .btn-ghost:hover{border-color:rgba(255,255,255,.4)}\r\n  .btn-more{border-color:rgba(79,214,230,.32);color:var(--cyan);background:rgba(79,214,230,.055);box-shadow:none}\r\n  .btn-more:hover{border-color:rgba(79,214,230,.58);background:rgba(79,214,230,.095);transform:translateY(-2px)}\r\n  @media(min-width:1040px){.navlinks{display:flex}}\r\n  /* HERO */\r\n  .hero{position:relative;padding:88px 0 68px;overflow:hidden}\r\n  .hero .inner{position:relative;z-index:2;max-width:980px}\r\n  .hero h1{font-family:'Geist';font-weight:800;font-size:66px;line-height:1.03;letter-spacing:0;margin:22px 0 0;max-width:100%;overflow-wrap:break-word}\r\n  .hero p.lead{margin-top:24px;font-size:19px;line-height:1.6;color:var(--muted);max-width:620px;overflow-wrap:anywhere}\r\n  /* DATA FLOW — hero illustration */\r\n  .data-flow{position:relative;margin:64px auto 0;width:100%;max-width:1100px;min-height:300px}\r\n  .df-svg{position:absolute;inset:0;width:100%;height:100%;pointer-events:none;overflow:visible;z-index:0}\r\n  .df-path{fill:none;stroke:rgba(79,214,230,.18);stroke-width:1.5;stroke-dasharray:6 8;animation:df-dash 1.1s linear infinite}\r\n  .df-path-out{stroke:rgba(100,230,162,.16)}\r\n  @keyframes df-dash{to{stroke-dashoffset:-14}}\r\n  .df-pulse{fill:var(--cyan)}\r\n  .df-svg:not(.is-ready){display:none!important}\r\n  .df-svg [data-df-dot]{opacity:0;filter:none}\r\n  .df-svg.is-ready [data-df-dot]{opacity:1}\r\n  .df-svg.is-ready [data-df-dot=\"in-1\"]{opacity:.8}\r\n  .df-svg.is-ready [data-df-dot=\"in-2\"]{opacity:.85}\r\n  .df-grid{position:relative;z-index:1;display:grid;grid-template-columns:210px 1fr 230px;gap:18px 48px;align-items:center;justify-content:center;width:max-content;max-width:100%;margin:0 auto;padding:12px 14px 0}\r\n  .df-col{display:flex;flex-direction:column;gap:14px;justify-content:center;width:210px}\r\n  .df-col-out{gap:16px;width:230px}\r\n  .df-node{display:flex;align-items:center;gap:10px;padding:8px 14px 8px 8px;border-radius:999px;border:1px solid var(--line);background:rgba(9,17,40,.78);backdrop-filter:blur(8px);font-size:12px;font-weight:600;color:var(--ink);transition:border-color .35s,box-shadow .35s,transform .35s;white-space:nowrap;width:100%}\r\n  .df-logo-box{width:34px;height:34px;border-radius:10px;display:grid;place-items:center;flex:none;overflow:hidden}\r\n  .df-logo-box img{width:100%;height:100%;object-fit:contain;display:block}\r\n  .df-node.is-active{border-color:rgba(79,214,230,.55);box-shadow:0 0 0 1px rgba(79,214,230,.12),0 0 28px rgba(79,214,230,.18);transform:scale(1.02)}\r\n  .df-hub{width:100%;min-width:260px;max-width:320px;border:1px solid rgba(79,214,230,.28);border-radius:16px;padding:16px 18px 14px;background:linear-gradient(165deg,rgba(15,28,58,.94),rgba(7,14,32,.9));box-shadow:0 0 0 1px rgba(79,214,230,.05),0 20px 48px rgba(0,0,0,.38);display:flex;flex-direction:column;gap:14px;justify-self:center;position:relative}\r\n  .df-hub-mark{display:flex;justify-content:center}\r\n  .df-hub-pill{display:inline-flex;align-items:center;justify-content:center;padding:6px;border-radius:12px;border:1px solid rgba(79,214,230,.35);background:rgba(9,17,40,.55);box-shadow:0 0 24px rgba(79,214,230,.12)}\r\n  .df-hub-pill .df-logo-box{width:38px;height:38px;border-radius:9px}\r\n  .df-sov-corner{position:absolute;top:0;right:0;transform:translate(46%,-46%);z-index:5;display:inline-flex;align-items:center;gap:4px;padding:3px 6px 3px 5px;border-radius:999px;border:1px solid rgba(79,214,230,.35);background:rgba(8,16,36,.95);backdrop-filter:blur(8px);box-shadow:0 2px 10px rgba(0,0,0,.32),0 0 0 2px rgba(7,14,32,.92);color:var(--cyan);pointer-events:none}\r\n  .df-sov-lock{width:11px;height:11px;flex:none;display:block}\r\n  .df-sov-flag{width:15px;height:11px;border-radius:2px;flex:none;display:block;box-shadow:0 0 0 1px rgba(255,255,255,.12)}\r\n  .df-stages{display:flex;flex-direction:column;gap:10px}\r\n  .df-stage{display:flex;flex-direction:column;gap:5px}\r\n  .df-stage-name{font-size:10.5px;color:var(--muted);line-height:1.2;font-weight:500;transition:color .2s}\r\n  .df-stage-bar{height:4px;border-radius:99px;background:rgba(255,255,255,.1);overflow:hidden}\r\n  .df-stage-bar i{display:block;height:100%;width:0;border-radius:99px}\r\n  .df-stage:nth-child(1) .df-stage-bar i{background:var(--cyan);animation:df-prog-1 9s linear infinite}\r\n  .df-stage:nth-child(2) .df-stage-bar i{background:var(--blue);animation:df-prog-2 9s linear infinite}\r\n  .df-stage:nth-child(3) .df-stage-bar i{background:var(--green);animation:df-prog-3 9s linear infinite}\r\n  .df-stage:nth-child(4) .df-stage-bar i{background:var(--violet);animation:df-prog-4 9s linear infinite}\r\n  .df-stage:nth-child(1) .df-stage-name{animation:df-name-1 9s linear infinite}\r\n  .df-stage:nth-child(2) .df-stage-name{animation:df-name-2 9s linear infinite}\r\n  .df-stage:nth-child(3) .df-stage-name{animation:df-name-3 9s linear infinite}\r\n  .df-stage:nth-child(4) .df-stage-name{animation:df-name-4 9s linear infinite}\r\n  @keyframes df-prog-1{0%{width:0}18%{width:100%}88%{width:100%}100%{width:0}}\r\n  @keyframes df-prog-2{0%,18%{width:0}36%{width:100%}88%{width:100%}100%{width:0}}\r\n  @keyframes df-prog-3{0%,36%{width:0}54%{width:100%}88%{width:100%}100%{width:0}}\r\n  @keyframes df-prog-4{0%,54%{width:0}72%{width:100%}88%{width:100%}100%{width:0}}\r\n  @keyframes df-name-1{0%,17%{color:var(--muted)}18%,88%{color:var(--ink)}100%{color:var(--muted)}}\r\n  @keyframes df-name-2{0%,35%{color:var(--muted)}36%,88%{color:var(--ink)}100%{color:var(--muted)}}\r\n  @keyframes df-name-3{0%,53%{color:var(--muted)}54%,88%{color:var(--ink)}100%{color:var(--muted)}}\r\n  @keyframes df-name-4{0%,71%{color:var(--muted)}72%,88%{color:var(--ink)}100%{color:var(--muted)}}\r\n  .df-out{border:1px solid var(--line);border-radius:14px;padding:0;background:rgba(9,17,40,.72);backdrop-filter:blur(8px);overflow:visible;transition:border-color .35s;width:100%;position:relative}\r\n  @keyframes df-live{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.45;transform:scale(.85)}}\r\n  .df-out:hover{border-color:rgba(79,214,230,.28)}\r\n  .df-win-head{display:flex;align-items:center;justify-content:space-between;gap:8px;padding:8px 11px;border-bottom:1px solid rgba(255,255,255,.07);border-radius:14px 14px 0 0;font-size:9.5px;font-weight:600;color:var(--muted);background:rgba(255,255,255,.02)}\r\n  .df-win-title{display:inline-flex;align-items:center;gap:6px;min-width:0}\r\n  .df-win-logo{width:16px;height:16px;border-radius:4px;flex:none}\r\n  .df-win-dots{display:flex;gap:4px}\r\n  .df-win-dots i{width:6px;height:6px;border-radius:50%;background:rgba(255,255,255,.16)}\r\n  .df-win-dots i:first-child{background:rgba(255,100,100,.55)}\r\n  .df-win-dots i:nth-child(2){background:rgba(255,200,80,.55)}\r\n  .df-win-dots i:nth-child(3){background:rgba(100,230,162,.55)}\r\n  .df-win-live{display:inline-flex;align-items:center;gap:5px;color:var(--green);font-size:9px;font-weight:700;letter-spacing:.08em;text-transform:uppercase}\r\n  .df-win-live i{width:5px;height:5px;border-radius:50%;background:var(--green);animation:df-live 2s ease-in-out infinite}\r\n  .df-out-body{padding:10px 11px 11px;border-radius:0 0 14px 14px;overflow:hidden}\r\n  .df-dash-kpis{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:8px}\r\n  .df-kpi-tile{padding:7px 8px;border-radius:8px;border:1px solid rgba(255,255,255,.07);background:rgba(255,255,255,.03)}\r\n  .df-kpi-tile.accent{border-color:rgba(100,230,162,.22);background:rgba(100,230,162,.07)}\r\n  .df-kpi-val{display:block;font-family:'Geist';font-size:14px;font-weight:800;line-height:1.1;color:var(--ink)}\r\n  .df-kpi-tile.accent .df-kpi-val{color:var(--green)}\r\n  .df-kpi-lbl{display:block;margin-top:2px;font-size:9px;color:var(--muted);letter-spacing:.04em}\r\n  .df-mini-bars{display:flex;align-items:flex-end;gap:6px;height:44px;padding:4px 2px 0}\r\n  .df-mini-bar{flex:1;border-radius:3px 3px 1px 1px;background:var(--cyan);transform-origin:bottom;transform:scaleY(0);opacity:.35}\r\n  .df-mini-bar:nth-child(1){height:42%;animation:df-bar-in 2.8s ease-in-out infinite}\r\n  .df-mini-bar:nth-child(2){height:68%;animation:df-bar-in 2.8s ease-in-out .15s infinite}\r\n  .df-mini-bar:nth-child(3){height:50%;animation:df-bar-in 2.8s ease-in-out .3s infinite}\r\n  .df-mini-bar:nth-child(4){height:88%;animation:df-bar-in 2.8s ease-in-out .45s infinite}\r\n  .df-mini-bar:nth-child(5){height:58%;animation:df-bar-in 2.8s ease-in-out .6s infinite}\r\n  @keyframes df-bar-in{0%,100%{transform:scaleY(0);opacity:.25}35%,65%{transform:scaleY(1);opacity:1}}\r\n  .df-out-chat{border-color:rgba(177,143,214,.22)}\r\n  .df-chat-scene{display:flex;flex-direction:column;gap:7px;min-height:88px}\r\n  .df-bubble{max-width:94%;padding:7px 10px;border-radius:11px;font-size:10px;line-height:1.45;opacity:0;transform:translateY(6px)}\r\n  .df-bubble-user{align-self:flex-end;background:rgba(79,214,230,.14);border:1px solid rgba(79,214,230,.22);color:var(--ink);animation:df-chat-user 5s ease-in-out infinite}\r\n  .df-bubble-ai{align-self:flex-start;background:rgba(255,255,255,.05);border:1px solid var(--line);color:var(--muted);animation:df-chat-ai 5s ease-in-out infinite}\r\n  .df-bubble-ai strong{color:var(--ink);font-weight:700}\r\n  .df-type-text{display:inline-block;overflow:hidden;white-space:nowrap;border-right:2px solid var(--cyan);max-width:0;animation:df-type 5s steps(32,end) infinite,df-caret .75s step-end infinite}\r\n  @keyframes df-chat-user{0%,8%{opacity:0;transform:translateY(6px)}12%,42%{opacity:1;transform:none}48%,100%{opacity:.85;transform:none}}\r\n  @keyframes df-chat-ai{0%,38%{opacity:0;transform:translateY(6px)}46%,92%{opacity:1;transform:none}100%{opacity:0;transform:translateY(4px)}}\r\n  @keyframes df-type{0%,10%{max-width:0}38%,88%{max-width:100%}100%{max-width:0}}\r\n  @keyframes df-caret{50%{border-color:transparent}}\r\n  @media(max-width:820px){\r\n    .data-flow{min-height:auto;margin:48px auto 0}\r\n    .df-grid{grid-template-columns:1fr;gap:28px;width:100%;padding:12px 10px 0}\r\n    .df-col,.df-col-out,.df-hub{width:100%;max-width:320px;justify-self:center}\r\n    .df-col.df-col-in{flex-direction:column;align-items:stretch;gap:10px}\r\n    .df-node{font-size:11.5px;width:100%;min-width:0;max-width:280px;margin:0 auto}\r\n    .df-svg.is-ready{opacity:.95}\r\n  }\r\n  @media(min-width:821px) and (max-width:980px){\r\n    .df-grid{gap:14px 24px}\r\n    .df-node{font-size:11px}\r\n    .df-hub{padding:14px}\r\n  }\r\n  @media (prefers-reduced-motion:reduce){\r\n    .df-path,.df-pulse,.df-stage-bar i,.df-stage-name,.df-mini-bar,.df-bubble,.df-type-text,.df-win-live i{animation:none!important}\r\n    .df-svg .df-pulse{display:none}\r\n    .df-svg [data-df-dot]{display:none}\r\n    .df-stage-bar i{width:100%}\r\n    .df-mini-bar{transform:scaleY(1);opacity:1}\r\n    .df-bubble-user,.df-bubble-ai{opacity:1;transform:none}\r\n    .df-type-text{max-width:100%;border-right:0}\r\n  }\r\n  .hero .hero-cta{margin-top:22px}\r\n  /* ENJEUX */\r\n  .pad{padding:80px 0}\r\n  .head{max-width:680px;margin-bottom:46px}\r\n  .head p{margin-top:16px;color:var(--muted);font-size:17px;line-height:1.6}\r\n  /* ENJEUX — sélecteur frein → levier */\r\n  .fx{display:grid;grid-template-columns:minmax(0,.92fr) minmax(0,1.08fr);gap:34px;align-items:stretch}\r\n  .fx-list{display:flex;flex-direction:column;gap:2px}\r\n  .fx-item{position:relative;display:flex;align-items:center;gap:13px;width:100%;text-align:left;border:0;background:transparent;color:inherit;cursor:pointer;padding:15px 14px;border-radius:10px;transition:.18s}\r\n  .fx-item::before{content:\"\";position:absolute;left:0;top:9px;bottom:9px;width:2px;border-radius:2px;background:transparent;transition:.18s}\r\n  .fx-item:hover{background:rgba(255,255,255,.035)}\r\n  .fx-item.on{background:rgba(255,211,106,.06)}\r\n  .fx-item.on::before{background:linear-gradient(180deg,#ffd36a,#f4a15a)}\r\n  .fx-ic{width:34px;height:34px;border-radius:10px;display:grid;place-items:center;font-size:17px;flex:none;background:rgba(255,255,255,.05);border:1px solid var(--line);transition:.18s;filter:grayscale(.4);opacity:.7}\r\n  .fx-item.on .fx-ic{background:rgba(255,211,106,.1);border-color:rgba(255,211,106,.3);filter:none;opacity:1}\r\n  .fx-tx{min-width:0}\r\n  .fx-tx b{display:block;font-family:'Geist';font-size:15px;font-weight:700;line-height:1.2}\r\n  .fx-tx span{display:block;font-size:12px;color:var(--muted);margin-top:2px;line-height:1.4;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\r\n  .fx-num{margin-left:auto;font-family:'Geist';font-size:12px;font-weight:700;color:var(--muted);opacity:.5;flex:none}\r\n  .fx-item.on .fx-num{color:#ffd36a;opacity:1}\r\n  /* panneau levier */\r\n  .fx-panel{position:relative;align-self:stretch;padding:30px 30px 30px 32px;display:flex}\r\n  .fx-panel::before{content:\"\";position:absolute;left:0;top:6px;bottom:6px;width:3px;border-radius:3px;background:linear-gradient(180deg,#ffd36a,#4fd6e6 48%,#64e6a2)}\r\n  .fx-card{position:absolute;inset:30px 30px 30px 32px;opacity:0;visibility:hidden;transform:translateY(8px);transition:opacity .35s ease,transform .35s ease;pointer-events:none}\r\n  .fx-card.on{position:relative;inset:auto;opacity:1;visibility:visible;transform:none;pointer-events:auto}\r\n  .fx-badge{display:inline-flex;align-items:center;gap:7px;font-size:10.5px;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:#acf6cc}\r\n  .fx-card .fx-big{width:52px;height:52px;border-radius:15px;display:grid;place-items:center;font-size:26px;background:rgba(100,230,162,.1);border:1px solid rgba(100,230,162,.26);margin:18px 0 16px}\r\n  .fx-card h4{font-family:'Geist';font-size:24px;font-weight:800;line-height:1.18}\r\n  .fx-card p{font-size:15px;color:var(--muted);line-height:1.62;margin-top:12px;max-width:440px}\r\n  .fx-arrow{display:inline-flex;align-items:center;gap:8px;margin-top:20px;font-size:12.5px;font-weight:700;color:var(--cyan);letter-spacing:.02em}\r\n  .fx-arrow .ln{width:30px;height:2px;border-radius:2px;background:linear-gradient(90deg,#ffd36a,#64e6a2)}\r\n  .enjeux-why{margin-top:48px;padding-top:40px;border-top:1px solid var(--line)}\r\n  .enjeux-why .head{margin-bottom:28px}\r\n  @media(max-width:820px){\r\n    .fx{grid-template-columns:1fr;gap:8px}\r\n    .fx-tx span{white-space:normal}\r\n    .fx-panel{padding:24px 4px 4px 20px;min-height:auto}\r\n    .fx-panel::before{top:2px;bottom:auto;height:46px}\r\n    .fx-card{position:absolute;inset:24px 4px 4px 20px}\r\n    .fx-card.on{position:relative;inset:auto}\r\n    .fx-card .fx-big{width:46px;height:46px;font-size:23px;margin:14px 0 12px}\r\n    .fx-card h4{font-size:21px}\r\n    .fx-card p{font-size:14px}\r\n  }\r\n  /* STEPS */\r\n  .steps-band{background:var(--navy-2)}\r\n  .steps{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:42px}\r\n  .step{position:relative;border:1px solid var(--line);border-radius:20px;padding:30px;background:var(--card);overflow:hidden}\r\n  .step:hover{border-color:rgba(79,214,230,.4)}\r\n  .step .k{font-family:'Geist';font-size:13px;letter-spacing:.2em;color:var(--cyan);font-weight:700}\r\n  .step h3{font-family:'Geist';font-size:26px;font-weight:800;margin:12px 0 4px}\r\n  .step .verb{font-size:12px;letter-spacing:.28em;text-transform:uppercase;color:var(--violet)}\r\n  .step p{margin-top:14px;color:var(--muted);font-size:14.5px;line-height:1.6}\r\n  .step .when{margin-top:18px;padding-top:16px;border-top:1px solid var(--line);font-size:13px;color:var(--ink);font-weight:600}\r\n  .step .big{position:absolute;right:18px;top:6px;font-family:'Geist';font-size:90px;font-weight:800;color:rgba(255,255,255,.04)}\r\n  @media(max-width:820px){.steps{grid-template-columns:1fr}}\r\n  /* SERVICES — accordion grid */\r\n  .svc-lead{margin-top:48px;max-width:640px}\r\n  .svc-lead h3{font-family:'Geist';font-size:24px;font-weight:800;line-height:1.2;margin-bottom:12px}\r\n  .svc-lead p{color:var(--muted);font-size:16px;line-height:1.6}\r\n  .svcs{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:28px;align-items:start}\r\n  .svc{display:flex;flex-direction:column;border:1px solid var(--line);border-radius:16px;background:var(--card);overflow:hidden;transition:border-color .22s,box-shadow .22s,transform .22s}\r\n  .svc:hover{border-color:rgba(79,214,230,.35);transform:translateY(-3px)}\r\n  .svc.is-open{border-color:rgba(79,214,230,.42);box-shadow:0 16px 44px rgba(0,0,0,.28);transform:none}\r\n  .svc-trigger{width:100%;display:block;position:relative;padding:24px 52px 20px 24px;background:none;border:none;color:inherit;cursor:pointer;text-align:left;font:inherit}\r\n  .svc-trigger:hover{background:rgba(255,255,255,.03)}\r\n  .svc .n{font-family:'Geist';font-size:13px;font-weight:700;color:var(--cyan);letter-spacing:.1em;display:block;margin-bottom:10px}\r\n  .svc-trigger-text h3{font-family:'Geist';font-size:18px;font-weight:700;line-height:1.25;margin:0 0 6px}\r\n  .svc .sub{font-size:13px;color:var(--violet);font-style:italic;display:block;line-height:1.45}\r\n  .svc-chev{position:absolute;top:20px;right:18px;width:28px;height:28px;border-radius:8px;border:1px solid var(--line);display:grid;place-items:center;color:var(--cyan);transition:transform .25s,border-color .22s}\r\n  .svc-chev svg{width:13px;height:13px}\r\n  .svc.is-open .svc-chev{transform:rotate(180deg);border-color:rgba(79,214,230,.45)}\r\n  .svc-panel{display:grid;grid-template-rows:0fr;transition:grid-template-rows .28s ease}\r\n  .svc.is-open .svc-panel{grid-template-rows:1fr}\r\n  .svc-panel-inner{overflow:hidden}\r\n  .svc-panel p{padding:0 24px 22px;font-size:14px;color:var(--muted);line-height:1.65;margin:0;border-top:1px solid var(--line);padding-top:16px}\r\n  @media(max-width:900px){.svcs{grid-template-columns:repeat(2,1fr)}}\r\n  @media(max-width:620px){.svcs{grid-template-columns:1fr;gap:12px}}\r\n  /* WHY */\r\n  .why{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:16px;margin-top:28px}\r\n  .why .it{display:flex;gap:14px;border:1px solid rgba(255,255,255,.14);border-radius:14px;padding:22px;background:linear-gradient(145deg,rgba(255,255,255,.055),rgba(255,255,255,.025));transition:.22s}\r\n  .why .it:hover{border-color:rgba(79,214,230,.36);transform:translateY(-3px)}\r\n  .why .it .ic{flex:none;width:40px;height:40px;border-radius:10px;background:var(--cyan);display:grid;place-items:center;color:#06122b;font-weight:800;font-family:'Geist'}\r\n  .why .it h4{font-family:'Geist';font-size:16px;margin-bottom:5px}\r\n  .why .it p{font-size:13.5px;color:var(--muted);line-height:1.5}\r\n  /* FOCUS SUMMARIES */\r\n  .focus-grid{display:grid;grid-template-columns:minmax(0,.9fr) minmax(0,1.1fr);gap:34px;align-items:start}\r\n  .focus-copy p{color:var(--muted);font-size:16px;line-height:1.65;margin-top:16px}\r\n  .focus-actions{display:flex;flex-wrap:wrap;gap:12px;margin-top:24px}\r\n  .focus-cards{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}\r\n  .focus-card{border:1px solid rgba(255,255,255,.14);border-radius:16px;padding:22px;background:linear-gradient(145deg,rgba(255,255,255,.055),rgba(255,255,255,.025));transition:.22s;min-height:164px}\r\n  .focus-card:hover{border-color:rgba(79,214,230,.34);transform:translateY(-3px)}\r\n  .focus-card .k{display:block;font-size:10.5px;letter-spacing:.16em;text-transform:uppercase;font-weight:800;color:var(--cyan);margin-bottom:9px}\r\n  .focus-card:nth-child(2) .k{color:var(--green)}\r\n  .focus-card:nth-child(3) .k{color:var(--violet)}\r\n  .focus-card h3{font-family:'Geist';font-size:18px;font-weight:800;line-height:1.2}\r\n  .focus-card p{font-size:13.5px;color:var(--muted);line-height:1.55;margin-top:9px}\r\n  .focus-logos{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px;margin-top:22px}\r\n  .focus-logo{height:74px;border:1px solid rgba(255,255,255,.18);border-radius:14px;background:#f7fbff;display:flex;align-items:center;justify-content:center;padding:14px}\r\n  .focus-logo img{max-width:100%;max-height:44px;object-fit:contain}\r\n  .focus-logo.logo-thales img{max-height:30px}\r\n  .focus-logo.logo-cert img{max-height:50px}\r\n  @media(max-width:900px){.focus-grid{grid-template-columns:1fr}.focus-cards{grid-template-columns:1fr 1fr}}\r\n  @media(max-width:620px){.focus-cards,.focus-logos{grid-template-columns:1fr}.focus-card{min-height:auto}}\r\n  /* CLIENTS */\r\n  .clients{display:grid;grid-template-columns:repeat(3,1fr);gap:18px;margin-top:40px}\r\n  .client{border:1px solid var(--line);border-radius:18px;padding:28px;background:var(--card);display:flex;flex-direction:column;gap:16px;min-height:245px}\r\n  .client-logo{height:112px;border-radius:14px;background:#f7fbff;border:1px solid rgba(255,255,255,.16);display:flex;align-items:center;justify-content:center;padding:18px}\r\n  .client-logo img{max-width:92%;max-height:82px;object-fit:contain}\r\n  .client .tag{font-size:11.5px;letter-spacing:.14em;text-transform:uppercase;color:var(--cyan);margin:8px 0 14px}\r\n  .client p{font-size:14px;color:var(--muted);line-height:1.55}\r\n  @media(max-width:760px){.clients{grid-template-columns:1fr}}\r\n  .quote{margin-top:34px;border:1px solid var(--line);border-radius:20px;padding:38px;background:var(--card)}\r\n  .quote p{font-size:19px;line-height:1.6;font-weight:300}\r\n  .quote p+p{margin-top:14px}\r\n  .quote .who{margin-top:24px;font-size:14px;color:var(--muted);display:flex;align-items:center;gap:14px}\r\n  .quote .avatar{width:54px;height:54px;border-radius:50%;object-fit:cover;border:1px solid rgba(255,255,255,.22)}\r\n  .quote .who b{color:var(--ink);font-family:'Geist'}\r\n  /* TECH */\r\n  .tech-grid{display:grid;grid-template-columns:1fr 1fr;gap:40px;align-items:start}\r\n  .offers{display:flex;flex-direction:column;gap:12px}\r\n  .offers div{border-left:2px solid rgba(79,214,230,.5);padding:12px 0 12px 16px;font-size:14px;color:var(--muted);line-height:1.55;background:linear-gradient(90deg,rgba(79,214,230,.055),transparent)}\r\n  .offers b{color:var(--cyan);font-family:'Geist'}\r\n  .logos{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;align-items:stretch}\r\n  .logobox{border:1px solid rgba(255,255,255,.2);border-radius:14px;padding:22px;display:flex;align-items:center;justify-content:center;background:#f7fbff;text-align:center;min-height:112px}\r\n  .logobox img{max-width:170px;width:100%;height:58px;object-fit:contain}\r\n  @media(max-width:820px){.tech-grid{grid-template-columns:1fr}}\r\n  /* IA */\r\n  .ia-sov{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:36px}\r\n  .ia-sov-card{border:1px solid var(--line);border-radius:16px;padding:22px 24px;background:var(--card);display:flex;flex-direction:column;gap:10px}\r\n  .ia-sov-card .sov-badge{display:inline-flex;align-items:center;width:max-content;padding:6px 14px;border-radius:999px;font-size:11px;font-weight:800;letter-spacing:.12em;text-transform:uppercase}\r\n  .ia-sov-card:first-child .sov-badge{background:rgba(79,214,230,.12);border:1px solid rgba(79,214,230,.28);color:var(--cyan)}\r\n  .ia-sov-card:last-child .sov-badge{background:rgba(177,143,214,.14);border:1px solid rgba(177,143,214,.32);color:#d4b8f0}\r\n  .ia-sov-card h4{font-family:'Geist';font-size:16px;font-weight:800;line-height:1.25}\r\n  .ia-sov-card p{font-size:13.5px;color:var(--muted);line-height:1.55}\r\n  .ia-sov-card .sov-tags{display:flex;flex-wrap:wrap;gap:6px;margin-top:4px}\r\n  .ia-sov-card .sov-tag{font-size:11px;padding:3px 9px;border-radius:6px;background:rgba(255,255,255,.05);border:1px solid var(--line);color:var(--muted)}\r\n  .ia-pillars{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-bottom:32px}\r\n  .ia-pillar{border:1px solid var(--line);border-radius:16px;padding:22px;background:var(--card);transition:.22s}\r\n  .ia-pillar:hover{border-color:rgba(79,214,230,.35);transform:translateY(-3px)}\r\n  .ia-pillar .pillar-label{font-size:10.5px;letter-spacing:.16em;text-transform:uppercase;font-weight:700;color:var(--cyan);margin-bottom:6px;display:block}\r\n  .ia-pillar:nth-child(2) .pillar-label{color:var(--green)}\r\n  .ia-pillar:nth-child(3) .pillar-label{color:var(--violet)}\r\n  .ia-pillar h3{font-family:'Geist';font-size:18px;font-weight:800;line-height:1.2;margin-bottom:8px}\r\n  .ia-pillar p{font-size:13.5px;color:var(--muted);line-height:1.55}\r\n  .ia-lock{display:flex;align-items:center;gap:10px;margin-bottom:32px;padding:10px 16px;border-radius:10px;border:1px solid rgba(79,214,230,.18);background:rgba(79,214,230,.04);font-size:12.5px;color:var(--muted);line-height:1.45}\r\n  .ia-lock strong{color:var(--cyan);font-weight:600;white-space:nowrap}\r\n  .ia-demo-grid{display:grid;grid-template-columns:1fr 1fr;gap:28px;align-items:start}\r\n  .ia-demo-left h3{font-family:'Geist';font-size:22px;font-weight:800;line-height:1.2;margin-top:10px}\r\n  .ia-demo-left p{font-size:14px;color:var(--muted);line-height:1.6;margin-top:10px}\r\n  .ia-demo-steps{display:flex;flex-direction:column;gap:14px;margin-top:16px}\r\n  .ia-demo-step{display:flex;align-items:flex-start;gap:14px}\r\n  .ia-demo-num{width:32px;height:32px;border-radius:10px;background:rgba(79,214,230,.12);border:1px solid rgba(79,214,230,.24);display:grid;place-items:center;font-family:'Geist';font-size:14px;font-weight:800;color:var(--cyan);flex:none}\r\n  .ia-demo-step p{font-size:14px;color:var(--muted);line-height:1.55;margin:0}\r\n  .ia-demo-step p strong{color:var(--ink)}\r\n  .ia-chat-panel{max-width:100%}\r\n  .ia-chat-panel .df-win-head{padding:10px 14px;font-size:12px}\r\n  .ia-chat-panel .df-win-logo{width:18px;height:18px}\r\n  .ia-chat-panel .df-out-body{padding:14px 16px 16px}\r\n  .ia-chat-panel .df-chat-scene{min-height:auto;gap:10px}\r\n  .ia-chat-panel .df-bubble{opacity:1;transform:none;animation:none!important;font-size:13px;padding:11px 14px;line-height:1.55;max-width:92%}\r\n  .ia-chat-panel .df-bubble-ai strong{color:var(--ink);font-weight:700}\r\n  .ia-chat-panel .tag-ok{display:inline-flex;align-items:center;gap:4px;margin-top:8px;padding:3px 9px;border-radius:6px;background:rgba(100,230,162,.1);border:1px solid rgba(100,230,162,.2);color:var(--green);font-size:11px;font-weight:700}\r\n  @media(max-width:900px){.ia-pillars{grid-template-columns:1fr}}\r\n  @media(max-width:760px){.ia-sov{grid-template-columns:1fr}.ia-demo-grid{grid-template-columns:1fr}.ia-lock{flex-direction:column;align-items:flex-start;gap:4px}}\r\n  /* TEAM */\r\n  .team{display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:18px;margin-top:40px}\r\n  .member{border:1px solid var(--line);border-radius:18px;background:var(--card);transition:.22s;text-align:center;padding:24px 18px}\r\n  .member:hover{transform:translateY(-5px);border-color:rgba(177,143,214,.45)}\r\n  .member .ph{width:132px;aspect-ratio:1;margin:0 auto 18px;overflow:hidden;background:#0a1228;border-radius:50%;border:1px solid var(--line)}\r\n  .member .ph img{width:100%;height:100%;object-fit:cover;filter:grayscale(1) contrast(1.05);transition:.4s}\r\n  .member:hover .ph img{filter:grayscale(0) contrast(1)}\r\n  .member .info{padding:0}\r\n  .member h4{font-family:'Geist';font-size:17px;font-weight:700}\r\n  .member .role{font-size:13px;color:var(--cyan);margin:4px 0 2px}\r\n  .member .exp{font-size:12px;color:var(--muted)}\r\n  /* DIAG + CONTACT */\r\n  .contact{display:grid;grid-template-columns:1fr 1.15fr;gap:44px;margin-top:40px}\r\n  .contact .lead p{color:var(--muted);line-height:1.65;font-size:15px;margin-top:16px}\r\n  .cinfo{margin-top:30px;display:flex;flex-direction:column;gap:16px}\r\n  .cinfo a,.cinfo div{display:flex;gap:14px;align-items:center;font-size:15px;color:var(--ink)}\r\n  .cinfo .ic{width:44px;height:44px;border-radius:13px;border:1px solid var(--line);display:grid;place-items:center;background:var(--card);font-size:18px;flex:none}\r\n  .cinfo small{display:block;color:var(--muted);font-size:12px}\r\n  form{border:1px solid var(--line);border-radius:20px;padding:30px;background:var(--card)}\r\n  .frow{display:grid;grid-template-columns:1fr 1fr;gap:16px}\r\n  .field{margin-bottom:16px}\r\n  label{display:block;font-size:13px;color:var(--muted);margin-bottom:7px}\r\n  input,textarea{width:100%;background:rgba(255,255,255,.04);border:1px solid var(--line);border-radius:11px;padding:13px 14px;color:var(--ink);font:inherit;font-size:14px;transition:.18s}\r\n  input:focus,textarea:focus{outline:none;border-color:var(--cyan);box-shadow:0 0 0 3px rgba(79,214,230,.15)}\r\n  textarea{min-height:120px;resize:vertical}\r\n  .priv{font-size:11.5px;color:var(--muted);line-height:1.5;margin:6px 0 18px}\r\n  .ok-msg{display:none;border:1px solid rgba(79,214,230,.4);background:rgba(79,214,230,.1);color:var(--ink);border-radius:12px;padding:16px;font-size:14px;margin-top:14px}\r\n  @media(max-width:820px){.contact{grid-template-columns:1fr}.frow{grid-template-columns:1fr}}\r\n  /* FOOTER */\r\n  footer.f{border-top:1px solid var(--line);margin-top:80px;padding:40px 0}\r\n  .frow2{display:flex;justify-content:space-between;flex-wrap:wrap;gap:20px;color:var(--muted);font-size:13px}\r\n  .frow2 .brand b{color:var(--ink)}\r\n  .frow2 .brand span{line-height:1.5}\r\n  .legal{display:flex;gap:16px;flex-wrap:wrap;align-items:center}\r\n  .legal a:hover{color:var(--ink)}\r\n  .reveal{opacity:0;transform:translateY(24px);transition:opacity .7s ease,transform .7s ease}\r\n  .reveal.in{opacity:1;transform:none}\r\n  @media(max-width:620px){\r\n    :root{--nav-h:65px}\r\n    .wrap{padding:0 18px}\r\n    nav.top .row{min-height:64px;gap:10px}\r\n    .brand{gap:10px}\r\n    .brand img{width:34px;height:34px}\r\n    .brand b{font-size:15px}\r\n    .btn{padding:11px 16px}\r\n    .eyebrow{letter-spacing:.18em}\r\n    .hero{padding:54px 0 48px}\r\n    h2{font-size:30px}\r\n    .hero h1{font-size:33px}\r\n    .hero p.lead{font-size:16px}\r\n    .pad{padding:58px 0}\r\n    .client{min-height:auto}\r\n    .quote{padding:26px}\r\n    .quote p{font-size:16px}\r\n    .quote .who{align-items:flex-start}\r\n    .logos{grid-template-columns:1fr 1fr}\r\n    .logobox{min-height:94px;padding:16px}\r\n    .frow2{flex-direction:column;align-items:flex-start;gap:22px}\r\n    .frow2 .brand{align-items:flex-start}\r\n    .legal{flex-direction:column;align-items:flex-start;gap:10px}\r\n  }\r\n  @media(max-width:380px){\r\n    nav.top .row{padding-left:14px;padding-right:14px}\r\n    .brand b{font-size:14px}\r\n    .hero h1{font-size:31px}\r\n  }\r\n\n  .hp-field{position:absolute!important;left:-10000px;top:auto;width:1px;height:1px;overflow:hidden}\n  button[disabled]{opacity:.72;cursor:wait}\n  .ok-msg[data-tone=\"error\"]{border-color:rgba(255,130,130,.34);background:rgba(255,90,90,.1);color:#ffd3d3}",
  "html": "<nav class=\"top\">\r\n  <div class=\"wrap row\">\r\n    <a class=\"brand\" href=\"#top\"><img src=\"/favicon.svg\" alt=\"\" /><b>OBSTRAKEN</b></a>\r\n    <div class=\"navlinks\">\r\n      <a href=\"#enjeux\">Enjeux</a>\r\n      <a href=\"#approche\">Approche</a>\r\n      <a href=\"#cloud-souverain\" class=\"nav-spot nav-spot-cloud\">Cloud souverain</a>\r\n      <a href=\"#ia\" class=\"nav-spot nav-spot-ia\">IA</a>\r\n      <a href=\"#references\">Références</a>\r\n      <a href=\"#tech\">Tech</a>\r\n      <a href=\"#equipe\">Équipe</a>\r\n      <a href=\"#contact\" class=\"nav-spot nav-spot-contact\">Contact</a>\r\n    </div>\r\n  </div>\r\n</nav>\r\n\r\n<header class=\"hero\" id=\"top\">\r\n  <div class=\"wrap\">\r\n    <div class=\"inner\">\r\n      <div class=\"eyebrow\">L'Usine de Données Souveraine as-a-Service</div>\r\n      <h1>Bâtisseur d'usines de données et d'IA<br/><span class=\"grad-t\">souveraines</span>.</h1>\r\n      <p class=\"lead\">Obstraken structure votre socle data de bout en bout : audit, cloud, gouvernance, dashboards et IA, avec une équipe senior unique pour passer d'une donnée dispersée à un pilotage fiable.</p>\r\n      <a class=\"btn btn-primary hero-cta\" href=\"#contact\">Discuter de votre projet<svg class=\"btn-arrow\" viewBox=\"0 0 28 16\" fill=\"none\" aria-hidden=\"true\"><path d=\"M0 8h22M16 2l6 6-6 6\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg></a>\r\n    </div>\r\n\r\n      <div class=\"data-flow reveal\" aria-label=\"Flux de données : sources dispersées vers usine Obstraken, puis analytics et IA\">\r\n        <svg class=\"df-svg\" aria-hidden=\"true\">\r\n          <path class=\"df-path\" id=\"df-line-in-0\" data-df-line=\"in-0\" d=\"M-999,-999\"/>\r\n          <path class=\"df-path\" id=\"df-line-in-1\" data-df-line=\"in-1\" d=\"M-999,-999\"/>\r\n          <path class=\"df-path\" id=\"df-line-in-2\" data-df-line=\"in-2\" d=\"M-999,-999\"/>\r\n          <path class=\"df-path df-path-out\" id=\"df-line-out-0\" data-df-line=\"out-0\" d=\"M-999,-999\"/>\r\n          <path class=\"df-path df-path-out\" id=\"df-line-out-1\" data-df-line=\"out-1\" d=\"M-999,-999\"/>\r\n          <circle class=\"df-pulse\" r=\"3\" data-df-dot=\"in-0\" cx=\"-9999\" cy=\"-9999\"/>\r\n          <circle class=\"df-pulse\" r=\"3\" data-df-dot=\"in-1\" cx=\"-9999\" cy=\"-9999\"/>\r\n          <circle class=\"df-pulse\" r=\"3\" data-df-dot=\"in-2\" cx=\"-9999\" cy=\"-9999\"/>\r\n          <circle r=\"3\" fill=\"#64e6a2\" data-df-dot=\"out-0\" cx=\"-9999\" cy=\"-9999\"/>\r\n          <circle r=\"3\" fill=\"#b18fd6\" data-df-dot=\"out-1\" cx=\"-9999\" cy=\"-9999\"/>\r\n        </svg>\r\n        <div class=\"df-grid\">\r\n          <div class=\"df-col df-col-in\">\r\n            <div class=\"df-node is-active\" data-df-src=\"0\">\r\n              <span class=\"df-logo-box\"><img src=\"/assets/sources/salesforce.png\" alt=\"\" /></span>\r\n              Salesforce\r\n            </div>\r\n            <div class=\"df-node\" data-df-src=\"1\">\r\n              <span class=\"df-logo-box\"><img src=\"/assets/sources/excel.png?v=2025\" alt=\"\" /></span>\r\n              Excel\r\n            </div>\r\n            <div class=\"df-node\" data-df-src=\"2\">\r\n              <span class=\"df-logo-box\"><img src=\"/assets/sources/postgresql.png\" alt=\"\" /></span>\r\n              PostgreSQL\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"df-hub\">\r\n            <span class=\"df-sov-corner\" title=\"Données hébergées en France\" aria-label=\"Souveraineté · France\"><svg class=\"df-sov-lock\" viewBox=\"0 0 24 24\" fill=\"none\" aria-hidden=\"true\"><path d=\"M7 11V8a5 5 0 0110 0v3\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"/><rect x=\"5\" y=\"11\" width=\"14\" height=\"10\" rx=\"2\" stroke=\"currentColor\" stroke-width=\"2\"/></svg><svg class=\"df-sov-flag\" viewBox=\"0 0 3 2\" aria-hidden=\"true\"><rect width=\"1\" height=\"2\" fill=\"#002395\"/><rect x=\"1\" width=\"1\" height=\"2\" fill=\"#fff\"/><rect x=\"2\" width=\"1\" height=\"2\" fill=\"#EF4135\"/></svg></span>\r\n            <div class=\"df-hub-mark\">\r\n              <span class=\"df-hub-pill\"><span class=\"df-logo-box\"><img src=\"/favicon.svg\" alt=\"Obstraken\" /></span></span>\r\n            </div>\r\n            <div class=\"df-stages\">\r\n              <div class=\"df-stage\" data-stage=\"0\"><span class=\"df-stage-name\">Ingestion &amp; connecteurs</span><span class=\"df-stage-bar\"><i></i></span></div>\r\n              <div class=\"df-stage\" data-stage=\"1\"><span class=\"df-stage-name\">Lakehouse &amp; DWH</span><span class=\"df-stage-bar\"><i></i></span></div>\r\n              <div class=\"df-stage\" data-stage=\"2\"><span class=\"df-stage-name\">Datamarts &amp; gouvernance</span><span class=\"df-stage-bar\"><i></i></span></div>\r\n              <div class=\"df-stage\" data-stage=\"3\"><span class=\"df-stage-name\">Couche sémantique &amp; IA</span><span class=\"df-stage-bar\"><i></i></span></div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"df-col df-col-out\">\r\n            <div class=\"df-out df-out-dash\" data-df-out=\"0\">\r\n              <span class=\"df-sov-corner\" title=\"Données hébergées en France\" aria-label=\"Souveraineté · France\"><svg class=\"df-sov-lock\" viewBox=\"0 0 24 24\" fill=\"none\" aria-hidden=\"true\"><path d=\"M7 11V8a5 5 0 0110 0v3\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"/><rect x=\"5\" y=\"11\" width=\"14\" height=\"10\" rx=\"2\" stroke=\"currentColor\" stroke-width=\"2\"/></svg><svg class=\"df-sov-flag\" viewBox=\"0 0 3 2\" aria-hidden=\"true\"><rect width=\"1\" height=\"2\" fill=\"#002395\"/><rect x=\"1\" width=\"1\" height=\"2\" fill=\"#fff\"/><rect x=\"2\" width=\"1\" height=\"2\" fill=\"#EF4135\"/></svg></span>\r\n              <div class=\"df-win-head\">\r\n                <span class=\"df-win-dots\"><i></i><i></i><i></i></span>\r\n                <span class=\"df-win-title\"><img class=\"df-win-logo\" src=\"/favicon.svg\" alt=\"\" />Tableau de bord</span>\r\n                <span class=\"df-win-live\"><i></i>Live</span>\r\n              </div>\r\n              <div class=\"df-out-body\">\r\n                <div class=\"df-dash-kpis\">\r\n                  <div class=\"df-kpi-tile\"><span class=\"df-kpi-val\">€3,9M</span><span class=\"df-kpi-lbl\">CA trimestre</span></div>\r\n                  <div class=\"df-kpi-tile accent\"><span class=\"df-kpi-val\">+12%</span><span class=\"df-kpi-lbl\">vs T-1</span></div>\r\n                </div>\r\n                <div class=\"df-mini-bars\" aria-hidden=\"true\">\r\n                  <div class=\"df-mini-bar\"></div><div class=\"df-mini-bar\"></div><div class=\"df-mini-bar\"></div><div class=\"df-mini-bar\"></div><div class=\"df-mini-bar\"></div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n            <div class=\"df-out df-out-chat\" data-df-out=\"1\">\r\n              <span class=\"df-sov-corner\" title=\"Données hébergées en France\" aria-label=\"Souveraineté · France\"><svg class=\"df-sov-lock\" viewBox=\"0 0 24 24\" fill=\"none\" aria-hidden=\"true\"><path d=\"M7 11V8a5 5 0 0110 0v3\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"/><rect x=\"5\" y=\"11\" width=\"14\" height=\"10\" rx=\"2\" stroke=\"currentColor\" stroke-width=\"2\"/></svg><svg class=\"df-sov-flag\" viewBox=\"0 0 3 2\" aria-hidden=\"true\"><rect width=\"1\" height=\"2\" fill=\"#002395\"/><rect x=\"1\" width=\"1\" height=\"2\" fill=\"#fff\"/><rect x=\"2\" width=\"1\" height=\"2\" fill=\"#EF4135\"/></svg></span>\r\n              <div class=\"df-win-head\">\r\n                <span class=\"df-win-dots\"><i></i><i></i><i></i></span>\r\n                <span class=\"df-win-title\"><img class=\"df-win-logo\" src=\"/favicon.svg\" alt=\"\" />Copilote IA</span>\r\n                <span class=\"df-win-live\" style=\"color:#dcc8f2\"><i style=\"background:#b18fd6\"></i>Actif</span>\r\n              </div>\r\n              <div class=\"df-out-body\">\r\n                <div class=\"df-chat-scene\">\r\n                  <div class=\"df-bubble df-bubble-user\"><span class=\"df-type-text\">Quel est notre churn ce trimestre ?</span></div>\r\n                  <div class=\"df-bubble df-bubble-ai\"><strong>4,2&nbsp;%</strong> — en baisse de 0,8 pt. Source&nbsp;: <em>clients.actifs</em></div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n  </div>\r\n</header>\r\n\r\n<!-- ENJEUX -->\r\n<section class=\"pad\" id=\"enjeux\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Enjeux</div>\r\n      <h2 style=\"margin-top:14px\">Freins actuels, leviers concrets.</h2>\r\n      <p>Obstraken commence par clarifier ce qui bloque, puis transforme chaque frein en décision, en sécurité et en automatisation exploitable.</p>\r\n    </div>\r\n    <div class=\"fx reveal\">\r\n      <div class=\"fx-list\" role=\"tablist\" aria-label=\"Freins\">\r\n        <button class=\"fx-item on\" role=\"tab\" aria-selected=\"true\" data-fx=\"0\">\r\n          <span class=\"fx-ic\">🧩</span>\r\n          <span class=\"fx-tx\"><b>Données dispersées</b><span>Les outils métiers ne se parlent pas.</span></span>\r\n          <span class=\"fx-num\">01</span>\r\n        </button>\r\n        <button class=\"fx-item\" role=\"tab\" aria-selected=\"false\" data-fx=\"1\">\r\n          <span class=\"fx-ic\">⏳</span>\r\n          <span class=\"fx-tx\"><b>Décisions trop lentes</b><span>Exports manuels, fichiers isolés, intuition.</span></span>\r\n          <span class=\"fx-num\">02</span>\r\n        </button>\r\n        <button class=\"fx-item\" role=\"tab\" aria-selected=\"false\" data-fx=\"2\">\r\n          <span class=\"fx-ic\">⚖️</span>\r\n          <span class=\"fx-tx\"><b>Conformité subie</b><span>RGPD, NIS2, cybersécurité, traçabilité.</span></span>\r\n          <span class=\"fx-num\">03</span>\r\n        </button>\r\n        <button class=\"fx-item\" role=\"tab\" aria-selected=\"false\" data-fx=\"3\">\r\n          <span class=\"fx-ic\">👥</span>\r\n          <span class=\"fx-tx\"><b>Manque d'équipe data</b><span>Compétences rares et déjà absorbées.</span></span>\r\n          <span class=\"fx-num\">04</span>\r\n        </button>\r\n      </div>\r\n      <div class=\"fx-panel\">\r\n        <div class=\"fx-card on\" role=\"tabpanel\" data-fx=\"0\">\r\n          <span class=\"fx-badge\">✅ Levier Obstraken</span>\r\n          <div class=\"fx-big\">🗄️</div>\r\n          <h4>Socle de données unifié</h4>\r\n          <p>Un socle unifié, gouverné et documenté, qui consolide sources, référentiels et indicateurs.</p>\r\n          <span class=\"fx-arrow\"><span class=\"ln\"></span>Données dispersées → données maîtrisées</span>\r\n        </div>\r\n        <div class=\"fx-card\" role=\"tabpanel\" data-fx=\"1\">\r\n          <span class=\"fx-badge\">✅ Levier Obstraken</span>\r\n          <div class=\"fx-big\">📊</div>\r\n          <h4>Pilotage en temps réel</h4>\r\n          <p>Des dashboards utiles, branchés sur des flux fiables, pour piloter à partir d'une donnée fraîche.</p>\r\n          <span class=\"fx-arrow\"><span class=\"ln\"></span>Décisions lentes → arbitrages rapides</span>\r\n        </div>\r\n        <div class=\"fx-card\" role=\"tabpanel\" data-fx=\"2\">\r\n          <span class=\"fx-badge\">✅ Levier Obstraken</span>\r\n          <div class=\"fx-big\">🛡️</div>\r\n          <h4>Conformité maîtrisée</h4>\r\n          <p>Une architecture cloud maîtrisée, des accès structurés et une documentation exploitable par vos équipes.</p>\r\n          <span class=\"fx-arrow\"><span class=\"ln\"></span>Conformité subie → conformité pilotée</span>\r\n        </div>\r\n        <div class=\"fx-card\" role=\"tabpanel\" data-fx=\"3\">\r\n          <span class=\"fx-badge\">✅ Levier Obstraken</span>\r\n          <div class=\"fx-big\">🤝</div>\r\n          <h4>Collectif senior A→Z</h4>\r\n          <p>Un collectif senior mobilisé de A à Z : cadrage, build, run, IA et transmission.</p>\r\n          <span class=\"fx-arrow\"><span class=\"ln\"></span>Manque d'équipe → équipe dédiée</span>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <div class=\"enjeux-why\">\r\n      <div class=\"head reveal\"><div class=\"eyebrow\">Pourquoi Obstraken</div><h2 style=\"margin-top:14px\">Six raisons d'avancer sereinement.</h2></div>\r\n      <div class=\"why\">\r\n        <div class=\"it reveal\"><div class=\"ic\">1</div><div><h4>Un seul contrat, de A à Z</h4><p>Un partenaire, un interlocuteur unique et senior du début à la fin.</p></div></div>\r\n        <div class=\"it reveal\"><div class=\"ic\">2</div><div><h4>Prix fixe tout inclus</h4><p>Pas de dérive, pas de surprise cloud.</p></div></div>\r\n        <div class=\"it reveal\"><div class=\"ic\">3</div><div><h4>Clouds de confiance</h4><p>GCP natif, S3NS et Azure selon vos contraintes de souveraineté.</p></div></div>\r\n        <div class=\"it reveal\"><div class=\"ic\">4</div><div><h4>Environnements réglementés</h4><p>Santé, pharma, médico-social : un terrain prouvé.</p></div></div>\r\n        <div class=\"it reveal\"><div class=\"ic\">5</div><div><h4>Résultats dès 6 semaines</h4><p>Un POC concret, vite, pour décider sur du tangible.</p></div></div>\r\n        <div class=\"it reveal\"><div class=\"ic\">6</div><div><h4>Data + IA intégrées</h4><p>3 ingénieurs IA dans le collectif, au cœur de la chaîne.</p></div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- STEPS -->\r\n<section class=\"steps-band pad\" id=\"approche\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Approche</div>\r\n      <h2 style=\"margin-top:14px\">Voir clair, construire, exploiter.</h2>\r\n      <p>Premiers résultats dès 6 semaines. Infrastructure complète en 6 mois. On la fait tourner pour vous — et vous restez maître de tout.</p>\r\n    </div>\r\n    <div class=\"steps\">\r\n      <div class=\"step reveal\"><span class=\"big\">01</span><div class=\"k\">NEXUS START</div><div class=\"verb\">Voir clair</div><h3>POC décisionnel</h3><p>POC fonctionnel avec 3 à 5 dashboards décisionnels pour prouver la valeur, vite.</p><div class=\"when\">6 à 12 semaines · Forfait</div></div>\r\n      <div class=\"step reveal\"><span class=\"big\">02</span><div class=\"k\">NEXUS BUILD</div><div class=\"verb\">Construire</div><h3>Infrastructure clé en main</h3><p>Infrastructure data complète, clé en main, déployée sur cloud souverain.</p><div class=\"when\">3 à 6 mois · Forfait jalons</div></div>\r\n      <div class=\"step reveal\"><span class=\"big\">03</span><div class=\"k\">NEXUS RUN</div><div class=\"verb\">Faire tourner</div><h3>Exploitation gérée</h3><p>Votre data tourne, évolue et reste conforme — vous n'y touchez pas.</p><div class=\"when\">12 à 36 mois · Tout inclus</div></div>\r\n    </div>\r\n    <div class=\"svc-lead reveal\" id=\"services\">\r\n      <h3>9 briques, un interlocuteur.</h3>\r\n      <p>Du diagnostic à la documentation, tout le cycle de vie de la donnée est couvert — ouvrez celles qui vous intéressent.</p>\r\n    </div>\r\n    <div class=\"svcs\">\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">01</span><span class=\"svc-trigger-text\"><h3>Audit &amp; Conseil stratégique</h3><span class=\"sub\">Le diagnostic avant l'ingénierie.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Cartographie des systèmes et des métiers, analyse des processus, formalisation du schéma directeur data. Nous posons les fondations stratégiques avant la moindre brique technique.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">02</span><span class=\"svc-trigger-text\"><h3>Infrastructure souveraine</h3><span class=\"sub\">Le socle technique sécurisé.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Conception et déploiement automatisés d'infrastructures cloud souveraines : S3NS (Thales &amp; Google Cloud). Sauvegarde, PRA et résilience intégrés dès la conception. Aucune zone d'ombre.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">03</span><span class=\"svc-trigger-text\"><h3>Chaîne data complète</h3><span class=\"sub\">De la source à la décision.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Connexions aux sources, datalake, ODS, flux de transformation, DWH, datamarts. Conception industrielle, sécurisée et performante, de l'ingestion à la restitution.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">04</span><span class=\"svc-trigger-text\"><h3>Master Data Management</h3><span class=\"sub\">La donnée fiable, par construction.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Référentiels unifiés, qualité mesurée en continu, modification des données dans le socle et alimentation de vos systèmes depuis le DWH. Aucune décision sérieuse sur une donnée incertaine.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">05</span><span class=\"svc-trigger-text\"><h3>Gouvernance &amp; Comitologie</h3><span class=\"sub\">Le cadre qui structure la donnée.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Politiques de données, instances de pilotage, gestion des utilisateurs et des accès. Un cadre clair qui garantit traçabilité, conformité RGPD et maîtrise opérationnelle dans la durée.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">06</span><span class=\"svc-trigger-text\"><h3>Dashboards</h3><span class=\"sub\">L'intelligence restituée.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Pilotage stratégique, indicateurs de qualité. Des visualisations pensées pour décider. Chaque indicateur sert une intention métier actionnable.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">07</span><span class=\"svc-trigger-text\"><h3>Obstraken Data Hub</h3><span class=\"sub\">Le hub de données externes.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Donnée gouvernementale, INSEE, météo, données sectorielles… Nous croisons vos données internes avec nos données externes pour décupler la puissance d'analyse et la force de l'IA.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">08</span><span class=\"svc-trigger-text\"><h3>Intelligence Artificielle</h3><span class=\"sub\">L'IA au service de l'industrialisation.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Intégration de briques d'IA dans la chaîne data : modèles prédictifs, analyses avancées, automatisation des traitements. Une IA ancrée dans vos données et alignée sur vos enjeux métier.</p></div></div></div>\r\n      <div class=\"svc reveal\"><button type=\"button\" class=\"svc-trigger\" aria-expanded=\"false\"><span class=\"svc-trigger-main\"><span class=\"n\">09</span><span class=\"svc-trigger-text\"><h3>Documentation</h3><span class=\"sub\">Ce qui rend l'usine pérenne.</span></span></span><span class=\"svc-chev\" aria-hidden=\"true\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 9l6 6 6-6\"/></svg></span></button><div class=\"svc-panel\"><div class=\"svc-panel-inner\"><p>Une vingtaine de livrables documentaires structurés : architecture, exploitation, sécurité, gouvernance. Une usine de données transmissible, auditable et maintenable dans la durée.</p></div></div></div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- CLOUD SOUVERAIN -->\r\n<section class=\"pad\" id=\"cloud-souverain\" style=\"background:var(--navy-2)\">\r\n  <div class=\"wrap\">\r\n    <div class=\"focus-grid\">\r\n      <div class=\"focus-copy reveal\">\r\n        <div class=\"eyebrow\">Cloud souverain</div>\r\n        <h2 style=\"margin-top:14px\">Le bon niveau de confiance, sans ralentir vos projets data.</h2>\r\n        <p>Nous concevons des socles cloud adaptés à la sensibilité de vos données : GCP France pour accélérer avec les services managés, S3NS / PREMI3NS pour les exigences SecNumCloud, et une architecture pensée pour la sécurité, la traçabilité et l'exploitation dans la durée.</p>\r\n        <div class=\"focus-actions\">\r\n          <a class=\"btn btn-more\" href=\"/cloud-souverain\">En voir + sur le Cloud Souverain</a>\r\n        </div>\r\n        <div class=\"focus-logos reveal\" aria-label=\"Partenaires et cadres cloud souverain\">\r\n          <div class=\"focus-logo\"><img src=\"/assets/partners/s3ns.png\" alt=\"S3NS\" /></div>\r\n          <div class=\"focus-logo\"><img src=\"/assets/partners/googlecloud.png\" alt=\"Google Cloud\" /></div>\r\n          <div class=\"focus-logo logo-thales\"><img src=\"/assets/partners/thales.png\" alt=\"Thales\" /></div>\r\n        </div>\r\n      </div>\r\n      <div class=\"focus-cards reveal\">\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">01 · Localisation</span>\r\n          <h3>Données hébergées en France</h3>\r\n          <p>Choix des régions, séparation des environnements et contrôle des flux entrants et sortants.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">02 · Confiance</span>\r\n          <h3>S3NS / PREMI3NS</h3>\r\n          <p>Cloud de confiance basé sur la technologie Google Cloud, opéré dans un cadre français contrôlé par Thales.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">03 · Sécurité</span>\r\n          <h3>Chiffrement, accès, audit</h3>\r\n          <p>IAM, clés, journalisation, sauvegardes, PRA et règles d'administration documentées dès la conception.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">04 · Run</span>\r\n          <h3>Exploitation maîtrisée</h3>\r\n          <p>Supervision, coûts, incidents et évolutions suivis dans un modèle clair pour vos équipes métier et IT.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- IA -->\r\n<section class=\"pad\" id=\"ia\">\r\n  <div class=\"wrap\">\r\n    <div class=\"focus-grid\">\r\n      <div class=\"focus-copy reveal\">\r\n        <div class=\"eyebrow\">Intelligence Artificielle</div>\r\n        <h2 style=\"margin-top:14px\">Une IA utile parce que la donnée est fiable.</h2>\r\n        <p>Obstraken intègre l'IA au bout de la chaîne data : modèles prédictifs, agents d'automatisation, copilotes métier et alertes en langage naturel. Vos données sont structurées, vos accès contrôlés, et les usages IA restent dans le périmètre contractuel choisi.</p>\r\n        <div class=\"focus-actions\">\r\n          <a class=\"btn btn-more\" href=\"/ia\">En voir + sur l'IA</a>\r\n        </div>\r\n      </div>\r\n      <div class=\"focus-cards reveal\">\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">Anticiper</span>\r\n          <h3>Prédire</h3>\r\n          <p>Churn, charge, stock, scoring commercial : des modèles construits sur vos datamarts fiabilisés.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">Automatiser</span>\r\n          <h3>Surveiller</h3>\r\n          <p>Agents IA capables de générer rapports, alertes et dashboards à partir de règles métier validées.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">Augmenter</span>\r\n          <h3>Interroger</h3>\r\n          <p>Copilote conversationnel pour poser des questions en français et obtenir des réponses chiffrées.</p>\r\n        </div>\r\n        <div class=\"focus-card\">\r\n          <span class=\"k\">Sécuriser</span>\r\n          <h3>Encadrer</h3>\r\n          <p>Pas d'entraînement sur vos données, pas de transfert non maîtrisé, pas d'accès hors droits métier.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- REFERENCES -->\r\n<section class=\"pad\" id=\"references\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\"><div class=\"eyebrow\">Références</div><h2 style=\"margin-top:14px\">Des usines de données en production,<br/>dans des secteurs exigeants.</h2></div>\r\n    <div class=\"clients\">\r\n      <div class=\"client reveal\"><div class=\"client-logo\"><img src=\"/assets/clients/les-petits-chaperons-rouges-crop.png\" alt=\"Les Petits Chaperons Rouges\" /></div><div><div class=\"tag\">Médico-social · ~1 000 crèches</div><p>Datawarehouse, dashboards et pilotage opérationnel sur une base centralisée.</p></div></div>\r\n      <div class=\"client reveal\"><div class=\"client-logo\"><img src=\"/assets/clients/emeis-crop.png\" alt=\"emeis\" /></div><div><div class=\"tag\">Santé · ~220 EHPAD + 180 cliniques</div><p>Structuration d'une chaîne data fiable pour piloter des environnements multisites.</p></div></div>\r\n      <div class=\"client reveal\"><div class=\"client-logo\"><img src=\"/assets/clients/iqvia-crop.png\" alt=\"IQVIA\" /></div><div><div class=\"tag\">Pharma · leaders mondiaux</div><p>Performance commerciale et analytics pour les plus grands laboratoires mondiaux.</p></div></div>\r\n    </div>\r\n    <div class=\"quote reveal\">\r\n      <p>« La data n'est plus un sujet technique. Elle est devenue un levier de pilotage. Les résultats sont au-delà des attentes : une donnée centralisée, des indicateurs fiables, des tableaux de bord réellement utiles pour le pilotage. »</p>\r\n      <p>« Au-delà des livrables, c'est l'équipe qui fait la différence — exigence, transparence, sens du résultat… et plaisir de travailler ensemble. »</p>\r\n      <div class=\"who\"><img class=\"avatar\" src=\"/assets/testimonials/claire-bourrely.png\" alt=\"Claire Bourrely\" /><span><b>Claire Bourrely</b> — Directrice des Systèmes d'Information, LPCR (Les Petits Chaperons Rouges)</span></div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- TECH -->\r\n<section class=\"pad\" id=\"tech\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Tech</div>\r\n      <h2 style=\"margin-top:14px\">Cloud souverain, cloud natif et BI dans la même chaîne.</h2>\r\n      <p>Obstraken sait travailler sur GCP natif, S3NS, Azure et Qlik. L'objectif n'est pas d'empiler des outils : c'est de choisir le bon niveau de souveraineté, de sécurité et d'industrialisation pour vos données.</p>\r\n    </div>\r\n    <div class=\"tech-grid reveal\">\r\n      <div class=\"offers\">\r\n        <div><b>GCP natif</b> — services managés Google Cloud pour la data, l'IA et l'automatisation.</div>\r\n        <div><b>S3NS</b> — offres Google Cloud opérées et sécurisées par S3NS, société française contrôlée par Thales.</div>\r\n        <div><b>Azure</b> — intégration dans les environnements Microsoft existants.</div>\r\n        <div><b>Qlik</b> — dashboards et analytics lorsque la plateforme est déjà en place.</div>\r\n      </div>\r\n      <div class=\"logos\">\r\n        <div class=\"logobox\"><img src=\"/assets/partners/s3ns.png\" alt=\"S3NS\" /></div>\r\n        <div class=\"logobox\"><img src=\"/assets/partners/googlecloud.png\" alt=\"Google Cloud\" /></div>\r\n        <div class=\"logobox\"><img src=\"/assets/partners/azure.svg\" alt=\"Microsoft Azure\" /></div>\r\n        <div class=\"logobox\"><img src=\"/assets/partners/qlik.svg\" alt=\"Qlik\" /></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- TEAM -->\r\n<section class=\"pad\" id=\"equipe\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\"><div class=\"eyebrow\">Équipe</div><h2 style=\"margin-top:14px\">7 experts data : +100 ans d'expérience cumulés.</h2><p>Un collectif senior et pluridisciplinaire. Vous travaillerez nécessairement avec chacun d'entre eux.</p></div>\r\n    <div class=\"team\">\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/mikael.png\" alt=\"Mikael Cleuziou\" /></div><div class=\"info\"><h4>Mikael Cleuziou</h4><div class=\"role\">Fondateur · Cadrage &amp; Stratégie</div><div class=\"exp\">21 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/nico.png\" alt=\"Nicolas Pouzet\" /></div><div class=\"info\"><h4>Nicolas Pouzet</h4><div class=\"role\">Directeur de Projets</div><div class=\"exp\">20 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/yohan.png\" alt=\"Yohan Gornadha\" /></div><div class=\"info\"><h4>Yohan Gornadha</h4><div class=\"role\">Expert métier &amp; Designer</div><div class=\"exp\">14 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/david.png\" alt=\"David Bochert\" /></div><div class=\"info\"><h4>David Bochert</h4><div class=\"role\">Architecte</div><div class=\"exp\">34 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/gaspard.png\" alt=\"Gaspard Cothias Faure\" /></div><div class=\"info\"><h4>Gaspard Cothias Faure</h4><div class=\"role\">Ingénieur Industrialisation &amp; IA</div><div class=\"exp\">5 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/thibault.png\" alt=\"Thibault Lapp\" /></div><div class=\"info\"><h4>Thibault Lapp</h4><div class=\"role\">Ingénieur Modélisation &amp; IA</div><div class=\"exp\">4 ans d'expérience</div></div></div>\r\n      <div class=\"member reveal\"><div class=\"ph\"><img src=\"/assets/arno.png\" alt=\"Arno Clognier\" /></div><div class=\"info\"><h4>Arno Clognier</h4><div class=\"role\">Ingénieur Modélisation &amp; IA</div><div class=\"exp\">4 ans d'expérience</div></div></div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- CONTACT -->\r\n<section class=\"pad\" id=\"contact\">\r\n  <div class=\"wrap\">\r\n    <div class=\"contact\">\r\n      <div class=\"lead reveal\">\r\n        <div class=\"eyebrow\">Contactez-nous</div>\r\n        <h2 style=\"margin-top:14px\">Bâtissons ensemble votre usine de données.</h2>\r\n        <p>Vous avez un projet data à structurer, une infrastructure à fiabiliser ou des prises de décision à accélérer ? Collaborons. Écrivez-nous, nous vous répondrons dans les plus brefs délais.</p>\r\n        <div class=\"cinfo\">\r\n          <a href=\"mailto:team@obstraken.com\"><span class=\"ic\">✉️</span><span>team@obstraken.com<small>Email</small></span></a>\r\n          <a href=\"tel:+33607224926\"><span class=\"ic\">☎️</span><span>+33 6 07 22 49 26<small>Téléphone</small></span></a>\r\n          <div><span class=\"ic\">📍</span><span>Paris, France<small>Siège social</small></span></div>\r\n        </div>\r\n      </div>\r\n      <form id=\"cform\" class=\"reveal\" novalidate>\n        <div class=\"hp-field\" aria-hidden=\"true\"><label for=\"website\">Site web</label><input id=\"website\" name=\"website\" tabindex=\"-1\" autocomplete=\"off\" /></div>\r\n        <div class=\"frow\">\r\n          <div class=\"field\"><label for=\"n\">Nom *</label><input id=\"n\" name=\"nom\" required placeholder=\"Votre nom\" /></div>\r\n          <div class=\"field\"><label for=\"e\">Email *</label><input id=\"e\" type=\"email\" name=\"email\" required placeholder=\"vous@entreprise.com\" /></div>\r\n        </div>\r\n        <div class=\"frow\">\r\n          <div class=\"field\"><label for=\"s\">Société</label><input id=\"s\" name=\"societe\" placeholder=\"Votre organisation\" /></div>\r\n          <div class=\"field\"><label for=\"p\">Téléphone</label><input id=\"p\" name=\"tel\" placeholder=\"Optionnel\" /></div>\r\n        </div>\r\n        <div class=\"field\"><label for=\"m\">Votre projet *</label><textarea id=\"m\" name=\"message\" required placeholder=\"Décrivez votre besoin en quelques lignes…\"></textarea></div>\r\n        <p class=\"priv\">Les données transmises via ce formulaire sont traitées par OBSTRAKEN pour répondre à votre demande. Vous disposez d'un droit d'accès, de rectification et de suppression.</p>\r\n        <button type=\"submit\" class=\"btn btn-primary\" style=\"width:100%;justify-content:center\">Envoyer ma demande</button>\r\n        <div class=\"ok-msg\" id=\"ok\" role=\"status\" aria-live=\"polite\"></div>\r\n      </form>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<footer class=\"f\">\r\n  <div class=\"wrap frow2\">\r\n    <div class=\"brand\" style=\"gap:10px\"><img src=\"/favicon.svg\" alt=\"\" style=\"width:30px;height:30px;border-radius:8px\"/><span>© 2026 <b>OBSTRAKEN</b> — L'Usine de Données Souveraine as-a-Service</span></div>\r\n    <div class=\"legal\"><a href=\"/politique-confidentialite\">Politique de confidentialité</a><a href=\"/mentions-legales\">Mentions légales</a></div>\r\n  </div>\r\n</footer>"
};

export const cloudPage: RawPage = {
  "css": ":root{\r\n    --nav-h:69px; --navy:#0b1530; --navy-2:#091128; --card:rgba(255,255,255,.045); --cyan:#4fd6e6; --violet:#b18fd6; --blue:#7db4e0; --green:#64e6a2;\r\n    --ink:#eaf0ff; --muted:#9eb0d8; --line:rgba(255,255,255,.12); --section-line:rgba(255,255,255,.26);\r\n  }\r\n  *{box-sizing:border-box;margin:0;padding:0}\r\n  html{scroll-behavior:smooth;scroll-padding-top:var(--nav-h)}\r\n  html,body{max-width:100%;overflow-x:hidden}\r\n  body{font-family:'Geist',-apple-system,sans-serif;background:var(--navy);color:var(--ink);-webkit-font-smoothing:antialiased;padding-top:var(--nav-h)}\r\n  a{color:inherit;text-decoration:none}\r\n  .wrap{width:100%;max-width:1180px;margin:0 auto;padding:0 24px}\r\n  .grad-t{color:var(--cyan)}\r\n  .eyebrow{font-size:12px;letter-spacing:.32em;text-transform:uppercase;color:var(--cyan);font-weight:600;line-height:1.6;overflow-wrap:anywhere}\r\n  section{position:relative;border-top:1px solid var(--section-line)}\r\n  h1,h2,h3,h4{font-family:'Geist'}\r\n  h1{font-weight:800;font-size:64px;line-height:1.03;letter-spacing:0;max-width:960px;overflow-wrap:break-word}\r\n  h2{font-weight:800;font-size:40px;line-height:1.1;letter-spacing:0}\r\n  nav.top{position:fixed;top:0;left:0;right:0;width:100%;z-index:500;backdrop-filter:blur(14px);background:rgba(11,21,48,.9);border-bottom:1px solid var(--section-line);box-shadow:0 14px 34px rgba(0,0,0,.18)}\r\n  nav.top .row{display:flex;align-items:center;justify-content:space-between;min-height:68px;gap:18px}\r\n  .brand{display:flex;align-items:center;gap:12px}\r\n  .brand img{width:38px;height:38px;border-radius:9px}\r\n  .brand b{font-weight:800;letter-spacing:.04em;font-size:17px}\r\n  .btn{display:inline-flex;align-items:center;gap:9px;padding:11px 20px;border-radius:999px;font-weight:600;font-size:14px;transition:.2s;border:1px solid transparent;cursor:pointer}\r\n  .btn-primary{background:var(--cyan);color:#06122b;box-shadow:0 10px 24px rgba(79,214,230,.18)}\r\n  .btn-primary:hover{transform:translateY(-2px);box-shadow:0 14px 32px rgba(79,214,230,.24)}\r\n  .btn .btn-arrow{width:28px;height:16px;flex:none;margin-left:2px}\r\n  .btn-more{border-color:rgba(79,214,230,.32);color:var(--cyan);background:rgba(79,214,230,.055);box-shadow:none}\r\n  .btn-more:hover{border-color:rgba(79,214,230,.58);background:rgba(79,214,230,.095);transform:translateY(-2px)}\r\n  .page-hero{position:relative;padding:88px 0 68px;overflow:hidden}\r\n  .page-hero p{margin-top:24px;font-size:19px;line-height:1.6;color:var(--muted);max-width:740px;overflow-wrap:anywhere}\r\n  .hero-actions{display:flex;flex-wrap:wrap;gap:12px;margin-top:26px}\r\n  .pad{padding:80px 0}\r\n  .head{max-width:760px;margin-bottom:46px}\r\n  .head p{margin-top:16px;color:var(--muted);font-size:17px;line-height:1.6}\r\n  .cloud-modes{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}\r\n  .cloud-mode{position:relative;overflow:hidden;border:1px solid rgba(255,255,255,.14);border-radius:20px;padding:30px 26px;background:linear-gradient(155deg,rgba(255,255,255,.065),rgba(255,255,255,.025));transition:.25s;min-height:300px}\r\n  .cloud-mode:hover{border-color:rgba(100,230,162,.38);transform:translateY(-4px);box-shadow:0 24px 56px rgba(0,0,0,.24)}\r\n  .cloud-mode::before{content:\"\";position:absolute;inset:0 0 auto;height:3px;background:linear-gradient(90deg,var(--green),var(--cyan))}\r\n  .cloud-mode:nth-child(2)::before{background:linear-gradient(90deg,var(--cyan),var(--violet))}\r\n  .cloud-mode:nth-child(3)::before{background:linear-gradient(90deg,var(--violet),var(--blue))}\r\n  .mode-num{display:inline-flex;width:42px;height:42px;border-radius:13px;align-items:center;justify-content:center;background:rgba(100,230,162,.12);border:1px solid rgba(100,230,162,.24);color:var(--green);font-weight:800;margin-bottom:18px}\r\n  .cloud-mode:nth-child(2) .mode-num{background:rgba(79,214,230,.12);border-color:rgba(79,214,230,.24);color:var(--cyan)}\r\n  .cloud-mode:nth-child(3) .mode-num{background:rgba(177,143,214,.12);border-color:rgba(177,143,214,.24);color:var(--violet)}\r\n  .cloud-mode h3{font-size:23px;font-weight:800;line-height:1.15}\r\n  .cloud-mode p{font-size:14.5px;color:var(--muted);line-height:1.62;margin-top:13px}\r\n  .mode-tags{display:flex;flex-wrap:wrap;gap:8px;margin-top:18px}\r\n  .mode-tags span{font-size:11.5px;padding:4px 10px;border-radius:6px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);color:var(--muted);font-weight:500}\r\n  .logo-wall{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}\r\n  .logo-card{border:1px solid rgba(255,255,255,.16);border-radius:18px;background:linear-gradient(145deg,rgba(255,255,255,.055),rgba(255,255,255,.025));overflow:hidden;min-height:202px;display:flex;flex-direction:column}\r\n  .logo-box{height:118px;background:#f7fbff;display:flex;align-items:center;justify-content:center;padding:22px;border-bottom:1px solid rgba(255,255,255,.1)}\r\n  .logo-box img{max-width:100%;max-height:70px;object-fit:contain}\r\n  .logo-box.logo-thales img{max-height:34px}\r\n  .logo-box.logo-rep img{max-height:92px}\r\n  .logo-card .txt{padding:18px 20px}\r\n  .logo-card h3{font-size:16px;font-weight:800}\r\n  .logo-card p{font-size:13.5px;color:var(--muted);line-height:1.55;margin-top:8px}\r\n  .build-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}\r\n  .build-card{border:1px solid rgba(255,255,255,.14);border-radius:16px;padding:22px;background:var(--card);transition:.22s}\r\n  .build-card:hover{border-color:rgba(79,214,230,.35);transform:translateY(-3px)}\r\n  .build-card .k{display:block;font-size:10.5px;letter-spacing:.16em;text-transform:uppercase;font-weight:800;color:var(--cyan);margin-bottom:9px}\r\n  .build-card:nth-child(2) .k{color:var(--green)}\r\n  .build-card:nth-child(3) .k{color:var(--violet)}\r\n  .build-card:nth-child(4) .k{color:var(--blue)}\r\n  .build-card h3{font-size:18px;font-weight:800;line-height:1.2}\r\n  .build-card p{font-size:13.5px;color:var(--muted);line-height:1.55;margin-top:9px}\r\n  .timeline{display:grid;grid-template-columns:repeat(3,1fr);gap:20px}\r\n  .step{position:relative;border:1px solid var(--line);border-radius:20px;padding:30px;background:var(--card);overflow:hidden}\r\n  .step:hover{border-color:rgba(79,214,230,.4)}\r\n  .step .k{font-size:13px;letter-spacing:.2em;color:var(--cyan);font-weight:700}\r\n  .step h3{font-size:26px;font-weight:800;margin:12px 0 4px}\r\n  .step p{margin-top:14px;color:var(--muted);font-size:14.5px;line-height:1.6}\r\n  .step .big{position:absolute;right:18px;top:6px;font-size:90px;font-weight:800;color:rgba(255,255,255,.04)}\r\n  .cta-band{text-align:center;padding:20px 0 0}\r\n  .cta-band p{color:var(--muted);font-size:15px;margin-bottom:20px}\r\n  footer.f{border-top:1px solid var(--line);margin-top:80px;padding:40px 0}\r\n  .frow2{display:flex;justify-content:space-between;flex-wrap:wrap;gap:20px;color:var(--muted);font-size:13px}\r\n  .frow2 .brand b{color:var(--ink)}\r\n  .frow2 .brand span{line-height:1.5}\r\n  .legal{display:flex;gap:16px;flex-wrap:wrap;align-items:center}\r\n  .legal a:hover{color:var(--ink)}\r\n  .reveal{opacity:0;transform:translateY(24px);transition:opacity .7s ease,transform .7s ease}\r\n  .reveal.in{opacity:1;transform:none}\r\n  @media(max-width:980px){.cloud-modes{grid-template-columns:1fr}.build-grid{grid-template-columns:1fr 1fr}.logo-wall{grid-template-columns:repeat(2,1fr)}.timeline{grid-template-columns:1fr}}\r\n  @media(max-width:620px){\r\n    :root{--nav-h:65px}\r\n    .wrap{padding:0 18px}\r\n    nav.top .row{min-height:64px}\r\n    .brand img{width:34px;height:34px}\r\n    .brand b{font-size:15px}\r\n    h1{font-size:33px}\r\n    h2{font-size:30px}\r\n    .page-hero{padding:54px 0 48px}\r\n    .page-hero p{font-size:16px}\r\n    .pad{padding:58px 0}\r\n    .build-grid,.logo-wall{grid-template-columns:1fr}\r\n    .cloud-mode{min-height:auto;padding:24px 20px}\r\n    .frow2{flex-direction:column;align-items:flex-start;gap:22px}\r\n    .frow2 .brand{align-items:flex-start}\r\n    .legal{flex-direction:column;align-items:flex-start;gap:10px}\r\n  }",
  "html": "<nav class=\"top\">\r\n  <div class=\"wrap row\">\r\n    <a class=\"brand\" href=\"/#top\"><img src=\"/favicon.svg\" alt=\"\" /><b>OBSTRAKEN</b></a>\r\n  </div>\r\n</nav>\r\n\r\n<header class=\"page-hero\">\r\n  <div class=\"wrap\">\r\n    <div class=\"eyebrow\">Cloud souverain</div>\r\n    <h1 style=\"margin-top:22px\">Un socle cloud <span class=\"grad-t\">fiable</span>, gouverné et adapté à vos contraintes.</h1>\r\n    <p>Obstraken conçoit votre infrastructure data selon le bon niveau de souveraineté : cloud natif en France pour aller vite, Cloud de Confiance pour les données sensibles, et une exploitation documentée pour garder la maîtrise.</p>\r\n    <div class=\"hero-actions\">\r\n      <a class=\"btn btn-primary\" href=\"/#contact\">Discuter de votre socle cloud<svg class=\"btn-arrow\" viewBox=\"0 0 28 16\" fill=\"none\" aria-hidden=\"true\"><path d=\"M0 8h22M16 2l6 6-6 6\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg></a>\r\n    </div>\r\n  </div>\r\n</header>\r\n\r\n<section class=\"pad\" style=\"background:var(--navy-2)\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Niveaux de confiance</div>\r\n      <h2 style=\"margin-top:14px\">La souveraineté se choisit selon le risque, pas par réflexe.</h2>\r\n      <p>Nous cadrons vos données, vos usages et vos obligations avant de choisir l'architecture. L'objectif : éviter la surcomplexité tout en protégeant ce qui doit l'être.</p>\r\n    </div>\r\n    <div class=\"cloud-modes reveal\">\r\n      <div class=\"cloud-mode\">\r\n        <span class=\"mode-num\">01</span>\r\n        <h3>GCP France pour accélérer</h3>\r\n        <p>Quand le besoin est de livrer vite avec des services managés performants : BigQuery, orchestration, sécurité cloud native, IA et supervision dans des régions françaises.</p>\r\n        <div class=\"mode-tags\">\r\n          <span>Time-to-market</span>\r\n          <span>Services managés</span>\r\n          <span>Data &amp; IA</span>\r\n        </div>\r\n      </div>\r\n      <div class=\"cloud-mode\">\r\n        <span class=\"mode-num\">02</span>\r\n        <h3>S3NS / PREMI3NS pour le Cloud de Confiance</h3>\r\n        <p>Pour les contextes régulés ou sensibles : PREMI3NS, solution basée sur la technologie Google Cloud, qualifiée SecNumCloud 3.2 par l'ANSSI et portée par S3NS, société française contrôlée par Thales.</p>\r\n        <div class=\"mode-tags\">\r\n          <span>SecNumCloud 3.2</span>\r\n          <span>Thales</span>\r\n          <span>Google Cloud</span>\r\n        </div>\r\n      </div>\r\n      <div class=\"cloud-mode\">\r\n        <span class=\"mode-num\">03</span>\r\n        <h3>Architecture hybride si nécessaire</h3>\r\n        <p>Certains périmètres demandent une trajectoire progressive : séparation des workloads, migration par domaine, contrôle des flux, maintien temporaire de systèmes existants.</p>\r\n        <div class=\"mode-tags\">\r\n          <span>Migration progressive</span>\r\n          <span>Zones de confiance</span>\r\n          <span>Run maîtrisé</span>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Écosystème</div>\r\n      <h2 style=\"margin-top:14px\">Technologies, acteurs et cadres de confiance.</h2>\r\n      <p>Nous intégrons les briques cloud avec une lecture opérationnelle : où sont les données, qui administre, quels services sont utilisés, quels journaux prouvent la conformité.</p>\r\n    </div>\r\n    <div class=\"logo-wall reveal\">\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box\"><img src=\"/assets/partners/googlecloud.png\" alt=\"Google Cloud\" /></div>\r\n        <div class=\"txt\"><h3>Google Cloud</h3><p>Services managés pour data platform, analytics, automatisation et IA.</p></div>\r\n      </div>\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box\"><img src=\"/assets/partners/s3ns.png\" alt=\"S3NS\" /></div>\r\n        <div class=\"txt\"><h3>S3NS</h3><p>Cloud de confiance issu du partenariat Thales x Google Cloud.</p></div>\r\n      </div>\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box logo-thales\"><img src=\"/assets/partners/thales.png\" alt=\"Thales\" /></div>\r\n        <div class=\"txt\"><h3>Thales</h3><p>Expertise cybersécurité et contrôle français au cœur de S3NS.</p></div>\r\n      </div>\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box\"><img src=\"/assets/partners/secnumcloud.png\" alt=\"Visa de sécurité ANSSI SecNumCloud\" /></div>\r\n        <div class=\"txt\"><h3>SecNumCloud</h3><p>Référentiel ANSSI pour les offres cloud de confiance qualifiées.</p></div>\r\n      </div>\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box\"><img src=\"/assets/partners/hds.png\" alt=\"Logo HDS\" /></div>\r\n        <div class=\"txt\"><h3>HDS</h3><p>Repère clé lorsque des données de santé entrent dans le périmètre projet.</p></div>\r\n      </div>\r\n      <div class=\"logo-card\">\r\n        <div class=\"logo-box logo-rep\"><img src=\"/assets/partners/republique-francaise.png\" alt=\"République Française\" /></div>\r\n        <div class=\"txt\"><h3>Cadre français</h3><p>Une lecture de la souveraineté alignée avec vos contraintes réglementaires et publiques.</p></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\" style=\"background:var(--navy-2)\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Ce que nous construisons</div>\r\n      <h2 style=\"margin-top:14px\">Une infrastructure exploitable, pas seulement déployée.</h2>\r\n    </div>\r\n    <div class=\"build-grid reveal\">\r\n      <div class=\"build-card\">\r\n        <span class=\"k\">Architecture</span>\r\n        <h3>Landing zone data</h3>\r\n        <p>Réseau, projets, comptes, séparation des environnements, choix des services et règles de nommage.</p>\r\n      </div>\r\n      <div class=\"build-card\">\r\n        <span class=\"k\">Sécurité</span>\r\n        <h3>Contrôles d'accès</h3>\r\n        <p>IAM, secrets, clés, chiffrement, segmentation et traçabilité des actions d'administration.</p>\r\n      </div>\r\n      <div class=\"build-card\">\r\n        <span class=\"k\">Résilience</span>\r\n        <h3>Sauvegarde &amp; PRA</h3>\r\n        <p>Rétention, restauration, tests, reprise d'activité et documentation des scénarios critiques.</p>\r\n      </div>\r\n      <div class=\"build-card\">\r\n        <span class=\"k\">Run</span>\r\n        <h3>Exploitation continue</h3>\r\n        <p>Supervision, alerting, coûts, incidents, évolutions et rituels de gouvernance pour tenir dans la durée.</p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Trajectoire</div>\r\n      <h2 style=\"margin-top:14px\">Du cadrage au run, sans zone grise.</h2>\r\n    </div>\r\n    <div class=\"timeline\">\r\n      <div class=\"step reveal\">\r\n        <span class=\"big\">01</span>\r\n        <div class=\"k\">CADRER</div>\r\n        <h3>Classer les données</h3>\r\n        <p>Sensibilité, obligations, usages, flux, dépendances et arbitrage entre cloud natif, Cloud de Confiance ou approche hybride.</p>\r\n      </div>\r\n      <div class=\"step reveal\">\r\n        <span class=\"big\">02</span>\r\n        <div class=\"k\">DÉPLOYER</div>\r\n        <h3>Automatiser le socle</h3>\r\n        <p>Infrastructure as code, sécurité par défaut, accès documentés, chaînes data prêtes pour l'industrialisation.</p>\r\n      </div>\r\n      <div class=\"step reveal\">\r\n        <span class=\"big\">03</span>\r\n        <div class=\"k\">OPÉRER</div>\r\n        <h3>Faire vivre la plateforme</h3>\r\n        <p>Supervision, évolutions, coûts, conformité, documentation et transmission aux équipes concernées.</p>\r\n      </div>\r\n    </div>\r\n    <div class=\"cta-band reveal\">\r\n      <p>Le cloud souverain n'est pas une destination unique : c'est un niveau de confiance à ajuster à vos données.</p>\r\n      <a class=\"btn btn-primary\" href=\"/#contact\">Cadrer votre trajectoire cloud<svg class=\"btn-arrow\" viewBox=\"0 0 28 16\" fill=\"none\" aria-hidden=\"true\"><path d=\"M0 8h22M16 2l6 6-6 6\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg></a>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<footer class=\"f\">\r\n  <div class=\"wrap frow2\">\r\n    <div class=\"brand\" style=\"gap:10px\"><img src=\"/favicon.svg\" alt=\"\" style=\"width:30px;height:30px;border-radius:8px\"/><span>© 2026 <b>OBSTRAKEN</b> — L'Usine de Données Souveraine as-a-Service</span></div>\r\n    <div class=\"legal\"><a href=\"/politique-confidentialite\">Politique de confidentialité</a><a href=\"/mentions-legales\">Mentions légales</a></div>\r\n  </div>\r\n</footer>"
};

export const iaPage: RawPage = {
  "css": ":root{\r\n    --nav-h:69px; --navy:#0b1530; --navy-2:#091128; --card:rgba(255,255,255,.045); --cyan:#4fd6e6; --violet:#b18fd6; --blue:#7db4e0; --green:#64e6a2;\r\n    --ink:#eaf0ff; --muted:#9eb0d8; --line:rgba(255,255,255,.12); --section-line:rgba(255,255,255,.26);\r\n  }\r\n  *{box-sizing:border-box;margin:0;padding:0}\r\n  html{scroll-behavior:smooth;scroll-padding-top:var(--nav-h)}\r\n  html,body{max-width:100%;overflow-x:hidden}\r\n  body{font-family:'Geist',-apple-system,sans-serif;background:var(--navy);color:var(--ink);-webkit-font-smoothing:antialiased;padding-top:var(--nav-h)}\r\n  a{color:inherit;text-decoration:none}\r\n  .wrap{width:100%;max-width:1180px;margin:0 auto;padding:0 24px}\r\n  .grad-t{color:var(--cyan)}\r\n  .eyebrow{font-size:12px;letter-spacing:.32em;text-transform:uppercase;color:var(--cyan);font-weight:600;line-height:1.6;overflow-wrap:anywhere}\r\n  section{position:relative;border-top:1px solid var(--section-line)}\r\n  h1,h2,h3,h4{font-family:'Geist'}\r\n  h1{font-weight:800;font-size:64px;line-height:1.03;letter-spacing:0;max-width:920px;overflow-wrap:break-word}\r\n  h2{font-weight:800;font-size:40px;line-height:1.1;letter-spacing:0}\r\n  nav.top{position:fixed;top:0;left:0;right:0;width:100%;z-index:500;backdrop-filter:blur(14px);background:rgba(11,21,48,.9);border-bottom:1px solid var(--section-line);box-shadow:0 14px 34px rgba(0,0,0,.18)}\r\n  nav.top .row{display:flex;align-items:center;justify-content:space-between;min-height:68px;gap:18px}\r\n  .brand{display:flex;align-items:center;gap:12px}\r\n  .brand img{width:38px;height:38px;border-radius:9px}\r\n  .brand b{font-weight:800;letter-spacing:.04em;font-size:17px}\r\n  .btn{display:inline-flex;align-items:center;gap:9px;padding:11px 20px;border-radius:999px;font-weight:600;font-size:14px;transition:.2s;border:1px solid transparent;cursor:pointer}\r\n  .btn-primary{background:var(--cyan);color:#06122b;box-shadow:0 10px 24px rgba(79,214,230,.18)}\r\n  .btn-primary:hover{transform:translateY(-2px);box-shadow:0 14px 32px rgba(79,214,230,.24)}\r\n  .btn .btn-arrow{width:28px;height:16px;flex:none;margin-left:2px}\r\n  .btn-more{border-color:rgba(79,214,230,.32);color:var(--cyan);background:rgba(79,214,230,.055);box-shadow:none}\r\n  .btn-more:hover{border-color:rgba(79,214,230,.58);background:rgba(79,214,230,.095);transform:translateY(-2px)}\r\n  .page-hero{position:relative;padding:88px 0 68px;overflow:hidden}\r\n  .page-hero p{margin-top:24px;font-size:19px;line-height:1.6;color:var(--muted);max-width:720px;overflow-wrap:anywhere}\r\n  .hero-actions{display:flex;flex-wrap:wrap;gap:12px;margin-top:26px}\r\n  .pad{padding:80px 0}\r\n  .head{max-width:760px;margin-bottom:46px}\r\n  .head p{margin-top:16px;color:var(--muted);font-size:17px;line-height:1.6}\r\n  .ia-sov{display:grid;grid-template-columns:1fr 1fr;gap:2px;border-radius:18px;overflow:hidden}\r\n  .ia-sov-card{position:relative;padding:30px 28px;background:linear-gradient(150deg,rgba(255,255,255,.06),rgba(255,255,255,.025));display:flex;flex-direction:column;gap:14px}\r\n  .ia-sov-card::before{content:\"\";position:absolute;inset:0 0 auto;height:3px}\r\n  .ia-sov-card:first-child::before{background:linear-gradient(90deg,var(--cyan),var(--blue))}\r\n  .ia-sov-card:last-child::before{background:linear-gradient(90deg,var(--violet),#e07db4)}\r\n  .sov-badge{display:inline-flex;align-items:center;gap:8px;width:max-content;padding:6px 14px;border-radius:999px;font-size:11px;font-weight:800;letter-spacing:.12em;text-transform:uppercase}\r\n  .ia-sov-card:first-child .sov-badge{background:rgba(79,214,230,.12);border:1px solid rgba(79,214,230,.24);color:var(--cyan)}\r\n  .ia-sov-card:last-child .sov-badge{background:rgba(177,143,214,.14);border:1px solid rgba(177,143,214,.28);color:#d4b8f0}\r\n  .ia-sov-card h3{font-size:19px;font-weight:800;line-height:1.25}\r\n  .ia-sov-card p{font-size:14px;color:var(--muted);line-height:1.6}\r\n  .sov-tags{display:flex;flex-wrap:wrap;gap:8px;margin-top:4px}\r\n  .sov-tag{font-size:11.5px;padding:4px 10px;border-radius:6px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);color:var(--muted);font-weight:500}\r\n  .ia-pillars{display:grid;grid-template-columns:repeat(3,1fr);gap:20px}\r\n  .ia-pillar{position:relative;overflow:hidden;border:1px solid rgba(255,255,255,.14);border-radius:20px;padding:32px 28px 28px;background:linear-gradient(155deg,rgba(255,255,255,.065),rgba(255,255,255,.025));transition:.28s;display:flex;flex-direction:column}\r\n  .ia-pillar:hover{border-color:rgba(79,214,230,.42);transform:translateY(-5px);box-shadow:0 24px 56px rgba(0,0,0,.28)}\r\n  .pillar-icon{width:52px;height:52px;border-radius:14px;display:grid;place-items:center;font-size:24px;margin-bottom:20px;border:1px solid transparent}\r\n  .ia-pillar:nth-child(1) .pillar-icon{background:rgba(79,214,230,.12);border-color:rgba(79,214,230,.24)}\r\n  .ia-pillar:nth-child(2) .pillar-icon{background:rgba(100,230,162,.12);border-color:rgba(100,230,162,.24)}\r\n  .ia-pillar:nth-child(3) .pillar-icon{background:rgba(177,143,214,.12);border-color:rgba(177,143,214,.24)}\r\n  .pillar-label{font-size:11px;letter-spacing:.18em;text-transform:uppercase;font-weight:700;margin-bottom:6px;color:var(--cyan)}\r\n  .ia-pillar:nth-child(2) .pillar-label{color:var(--green)}\r\n  .ia-pillar:nth-child(3) .pillar-label{color:var(--violet)}\r\n  .ia-pillar h3{font-size:24px;font-weight:800;line-height:1.15;margin-bottom:14px}\r\n  .pillar-desc{font-size:14.5px;color:var(--muted);line-height:1.6;margin-bottom:22px;flex:1}\r\n  .pillar-usecases{border-top:1px solid var(--line);padding-top:18px;display:flex;flex-direction:column;gap:10px}\r\n  .usecase{display:flex;align-items:flex-start;gap:10px;font-size:13.5px;color:var(--muted);line-height:1.5}\r\n  .usecase::before{content:\"→\";color:var(--cyan);font-weight:700;flex:none;margin-top:1px}\r\n  .ia-sec-box{position:relative;border:2px solid rgba(79,214,230,.3);border-radius:22px;padding:36px 32px;background:linear-gradient(160deg,rgba(79,214,230,.06),rgba(11,21,48,.95));overflow:hidden}\r\n  .ia-sec-box::before{content:\"\";position:absolute;inset:0 0 auto;height:2px;background:linear-gradient(90deg,var(--cyan),var(--violet))}\r\n  .ia-sec-layers{display:flex;flex-direction:column;gap:0;max-width:720px;margin:0 auto}\r\n  .ia-sec-layer{display:flex;align-items:center;gap:16px;padding:14px 20px;position:relative}\r\n  .ia-sec-layer:not(:last-child)::after{content:\"\";position:absolute;left:32px;bottom:-1px;right:32px;height:1px;background:rgba(255,255,255,.08)}\r\n  .ia-sec-dot{width:10px;height:10px;border-radius:50%;flex:none}\r\n  .ia-sec-layer:nth-child(1) .ia-sec-dot{background:var(--cyan)}\r\n  .ia-sec-layer:nth-child(2) .ia-sec-dot{background:var(--green)}\r\n  .ia-sec-layer:nth-child(3) .ia-sec-dot{background:var(--violet)}\r\n  .ia-sec-layer:nth-child(4) .ia-sec-dot{background:var(--blue)}\r\n  .ia-sec-label{font-size:14px;color:var(--ink);font-weight:600;min-width:210px}\r\n  .ia-sec-detail{font-size:13px;color:var(--muted);line-height:1.5}\r\n  .ia-sec-footer{text-align:center;margin-top:24px;padding-top:20px;border-top:1px solid rgba(255,255,255,.08)}\r\n  .lock-msg{display:inline-flex;flex-direction:column;align-items:center;gap:6px;font-size:15px;font-weight:700;color:var(--cyan);letter-spacing:.04em}\r\n  .lock-sub{font-size:13px;color:var(--muted);font-weight:400;letter-spacing:0}\r\n  .ia-demo-grid{display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start}\r\n  .ia-demo-left h3{font-size:26px;font-weight:800;line-height:1.15;margin-top:10px}\r\n  .ia-demo-left p{font-size:15px;color:var(--muted);line-height:1.6;margin-top:12px}\r\n  .ia-demo-steps{display:flex;flex-direction:column;gap:14px;margin-top:20px}\r\n  .ia-demo-step{display:flex;align-items:flex-start;gap:14px}\r\n  .ia-demo-num{width:32px;height:32px;border-radius:10px;background:rgba(79,214,230,.12);border:1px solid rgba(79,214,230,.24);display:grid;place-items:center;font-size:14px;font-weight:800;color:var(--cyan);flex:none}\r\n  .ia-demo-step p{font-size:14px;color:var(--muted);line-height:1.55;margin:0}\r\n  .ia-demo-step p strong{color:var(--ink)}\r\n  .ia-chat{border:1px solid rgba(79,214,230,.22);border-radius:18px;background:linear-gradient(160deg,rgba(255,255,255,.05),rgba(255,255,255,.02));overflow:hidden}\r\n  .ia-chat-header{padding:14px 20px;border-bottom:1px solid rgba(255,255,255,.08);display:flex;align-items:center;gap:10px;font-size:13px;font-weight:600;color:var(--muted)}\r\n  .ia-chat-header .dot{width:8px;height:8px;border-radius:50%;background:var(--green);animation:pulse 2s ease-in-out infinite}\r\n  @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}\r\n  .ia-chat-body{padding:20px;display:flex;flex-direction:column;gap:14px}\r\n  .ia-chat-msg{max-width:88%;padding:12px 16px;border-radius:14px;font-size:13.5px;line-height:1.55}\r\n  .ia-chat-user{align-self:flex-end;background:rgba(79,214,230,.14);border:1px solid rgba(79,214,230,.2);color:var(--ink)}\r\n  .ia-chat-ai{align-self:flex-start;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);color:var(--muted)}\r\n  .ia-chat-ai strong{color:var(--ink);font-weight:600}\r\n  .tag-ok{display:inline-flex;align-items:center;gap:4px;margin-top:8px;padding:4px 10px;border-radius:6px;background:rgba(100,230,162,.12);border:1px solid rgba(100,230,162,.22);color:var(--green);font-size:11.5px;font-weight:700;letter-spacing:.05em}\r\n  .cta-band{text-align:center;padding:20px 0 0}\r\n  .cta-band p{color:var(--muted);font-size:15px;margin-bottom:20px}\r\n  footer.f{border-top:1px solid var(--line);margin-top:80px;padding:40px 0}\r\n  .frow2{display:flex;justify-content:space-between;flex-wrap:wrap;gap:20px;color:var(--muted);font-size:13px}\r\n  .frow2 .brand b{color:var(--ink)}\r\n  .frow2 .brand span{line-height:1.5}\r\n  .legal{display:flex;gap:16px;flex-wrap:wrap;align-items:center}\r\n  .legal a:hover{color:var(--ink)}\r\n  .reveal{opacity:0;transform:translateY(24px);transition:opacity .7s ease,transform .7s ease}\r\n  .reveal.in{opacity:1;transform:none}\r\n  @media(max-width:900px){.ia-pillars{grid-template-columns:1fr}.ia-demo-grid{grid-template-columns:1fr}}\r\n  @media(max-width:760px){.ia-sov{grid-template-columns:1fr}.ia-sec-layer{align-items:flex-start;flex-direction:column;gap:8px}.ia-sec-label{min-width:0}.ia-sec-layer:not(:last-child)::after{left:20px;right:20px}}\r\n  @media(max-width:620px){\r\n    :root{--nav-h:65px}\r\n    .wrap{padding:0 18px}\r\n    nav.top .row{min-height:64px}\r\n    .brand img{width:34px;height:34px}\r\n    .brand b{font-size:15px}\r\n    h1{font-size:33px}\r\n    h2{font-size:30px}\r\n    .page-hero{padding:54px 0 48px}\r\n    .page-hero p{font-size:16px}\r\n    .pad{padding:58px 0}\r\n    .ia-sov-card,.ia-pillar,.ia-sec-box{padding:24px 20px}\r\n    .frow2{flex-direction:column;align-items:flex-start;gap:22px}\r\n    .frow2 .brand{align-items:flex-start}\r\n    .legal{flex-direction:column;align-items:flex-start;gap:10px}\r\n  }",
  "html": "<nav class=\"top\">\r\n  <div class=\"wrap row\">\r\n    <a class=\"brand\" href=\"/#top\"><img src=\"/favicon.svg\" alt=\"\" /><b>OBSTRAKEN</b></a>\r\n  </div>\r\n</nav>\r\n\r\n<header class=\"page-hero\">\r\n  <div class=\"wrap\">\r\n    <div class=\"eyebrow\">Intelligence Artificielle</div>\r\n    <h1 style=\"margin-top:22px\">Des réponses <span class=\"grad-t\">justes</span>, des données fiables, un périmètre sécurisé.</h1>\r\n    <p>Nous fiabilisons et structurons vos données d'abord. L'IA peut ensuite produire des décisions éclairées, pas des approximations. Chaque usage est déployé dans le périmètre cloud et contractuel que vous choisissez.</p>\r\n    <div class=\"hero-actions\">\r\n      <a class=\"btn btn-primary\" href=\"/#contact\">Discuter de votre projet IA<svg class=\"btn-arrow\" viewBox=\"0 0 28 16\" fill=\"none\" aria-hidden=\"true\"><path d=\"M0 8h22M16 2l6 6-6 6\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg></a>\r\n    </div>\r\n  </div>\r\n</header>\r\n\r\n<section class=\"pad\" style=\"background:var(--navy-2)\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Souveraineté</div>\r\n      <h2 style=\"margin-top:14px\">Deux modes d'hébergement selon la sensibilité de vos usages.</h2>\r\n      <p>Le même principe dans les deux cas : vos données restent sous contrôle, vos accès sont bornés, et les modèles ne deviennent utiles qu'après une couche data propre, documentée et gouvernée.</p>\r\n    </div>\r\n    <div class=\"ia-sov reveal\">\r\n      <div class=\"ia-sov-card\">\r\n        <span class=\"sov-badge\">Mode GCP France</span>\r\n        <h3>IA sous contrats Google, instances France</h3>\r\n        <p>Pour accélérer avec les services managés Google Cloud en France : BigQuery, Vertex AI, Gemini et des modèles partenaires. L'objectif est de livrer vite, avec chiffrement, contrôle d'accès et traçabilité des traitements.</p>\r\n        <div class=\"sov-tags\">\r\n          <span class=\"sov-tag\">Gemini</span>\r\n          <span class=\"sov-tag\">Vertex AI</span>\r\n          <span class=\"sov-tag\">BigQuery ML</span>\r\n          <span class=\"sov-tag\">Région France</span>\r\n          <span class=\"sov-tag\">Contrats Google Cloud</span>\r\n        </div>\r\n      </div>\r\n      <div class=\"ia-sov-card\">\r\n        <span class=\"sov-badge\">Mode PREMI3NS</span>\r\n        <h3>IA 100% souveraine sur Cloud de Confiance</h3>\r\n        <p>Pour les secteurs régulés ou les données sensibles, les workloads IA peuvent être cadrés sur PREMI3NS, le Cloud de Confiance par S3NS, basé sur la technologie Google Cloud et qualifié SecNumCloud 3.2 par l'ANSSI.</p>\r\n        <div class=\"sov-tags\">\r\n          <span class=\"sov-tag\">S3NS / Thales</span>\r\n          <span class=\"sov-tag\">SecNumCloud 3.2</span>\r\n          <span class=\"sov-tag\">Données sensibles</span>\r\n          <span class=\"sov-tag\">Accès maîtrisés</span>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Paliers IA</div>\r\n      <h2 style=\"margin-top:14px\">Anticiper, automatiser, augmenter.</h2>\r\n      <p>Nous ne posons pas une couche IA sur une donnée fragile. Nous construisons d'abord le socle data, puis nous choisissons les usages qui créent vraiment de la valeur métier.</p>\r\n    </div>\r\n    <div class=\"ia-pillars reveal\">\r\n      <div class=\"ia-pillar\">\r\n        <div class=\"pillar-icon\">01</div>\r\n        <span class=\"pillar-label\">Palier 1</span>\r\n        <h3>Anticiper</h3>\r\n        <p class=\"pillar-desc\">Des modèles prédictifs entraînés sur vos datamarts pour transformer l'historique en prévisions actionnables.</p>\r\n        <div class=\"pillar-usecases\">\r\n          <div class=\"usecase\">Prédire le churn client plusieurs semaines avant qu'il arrive</div>\r\n          <div class=\"usecase\">Anticiper pics de charge, ruptures de stock ou dérives opérationnelles</div>\r\n          <div class=\"usecase\">Scorer la probabilité de signature d'une affaire commerciale</div>\r\n        </div>\r\n      </div>\r\n      <div class=\"ia-pillar\">\r\n        <div class=\"pillar-icon\">02</div>\r\n        <span class=\"pillar-label\">Palier 2</span>\r\n        <h3>Automatiser</h3>\r\n        <p class=\"pillar-desc\">Des agents IA qui surveillent vos KPIs, génèrent vos rapports et déclenchent des alertes sur des règles contrôlées.</p>\r\n        <div class=\"pillar-usecases\">\r\n          <div class=\"usecase\">Génération automatique de tableaux de bord à la demande</div>\r\n          <div class=\"usecase\">Alertes business personnalisées en langage naturel</div>\r\n          <div class=\"usecase\">Détection d'anomalies et notification aux équipes concernées</div>\r\n        </div>\r\n      </div>\r\n      <div class=\"ia-pillar\">\r\n        <div class=\"pillar-icon\">03</div>\r\n        <span class=\"pillar-label\">Palier 3</span>\r\n        <h3>Augmenter</h3>\r\n        <p class=\"pillar-desc\">Un copilote conversationnel déployé dans votre environnement, qui interroge vos données et ne voit que ce que vous autorisez.</p>\r\n        <div class=\"pillar-usecases\">\r\n          <div class=\"usecase\">Questions métier en français, réponses chiffrées et sourcées</div>\r\n          <div class=\"usecase\">Exploration de données sans écrire de SQL</div>\r\n          <div class=\"usecase\">Synthèses contextuelles pour accélérer la prise de décision</div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\" style=\"background:var(--navy-2)\">\r\n  <div class=\"wrap\">\r\n    <div class=\"head reveal\">\r\n      <div class=\"eyebrow\">Sécurité</div>\r\n      <h2 style=\"margin-top:14px\">Une IA encadrée par l'architecture, pas par la confiance aveugle.</h2>\r\n    </div>\r\n    <div class=\"ia-sec-box reveal\">\r\n      <div class=\"ia-sec-layers\">\r\n        <div class=\"ia-sec-layer\">\r\n          <div class=\"ia-sec-dot\"></div>\r\n          <div class=\"ia-sec-label\">Vos données</div>\r\n          <div class=\"ia-sec-detail\">Datamarts structurés, historisés, contrôlés et documentés avant tout usage IA.</div>\r\n        </div>\r\n        <div class=\"ia-sec-layer\">\r\n          <div class=\"ia-sec-dot\"></div>\r\n          <div class=\"ia-sec-label\">IA Obstraken</div>\r\n          <div class=\"ia-sec-detail\">Modèles, agents et copilotes conçus autour de vos droits métier et de vos règles de gouvernance.</div>\r\n        </div>\r\n        <div class=\"ia-sec-layer\">\r\n          <div class=\"ia-sec-dot\"></div>\r\n          <div class=\"ia-sec-label\">Infrastructure cloud</div>\r\n          <div class=\"ia-sec-detail\">GCP France ou PREMI3NS selon le niveau de souveraineté et de conformité attendu.</div>\r\n        </div>\r\n        <div class=\"ia-sec-layer\">\r\n          <div class=\"ia-sec-dot\"></div>\r\n          <div class=\"ia-sec-label\">Contrats et contrôles</div>\r\n          <div class=\"ia-sec-detail\">Chiffrement, journalisation, accès, séparation des rôles et politiques d'usage formalisées.</div>\r\n        </div>\r\n      </div>\r\n      <div class=\"ia-sec-footer\">\r\n        <span class=\"lock-msg\">\r\n          Rien ne sort du périmètre retenu.\r\n          <span class=\"lock-sub\">Pas d'entraînement sur vos données, pas d'accès tiers non prévu, pas de transfert non maîtrisé.</span>\r\n        </span>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"pad\">\r\n  <div class=\"wrap\">\r\n    <div class=\"ia-demo-grid reveal\">\r\n      <div class=\"ia-demo-left\">\r\n        <div class=\"eyebrow\">Résultat concret</div>\r\n        <h3>Vos utilisateurs créent leurs propres alertes métier en français.</h3>\r\n        <p>Plus besoin de ticket IT pour chaque règle simple. L'utilisateur décrit son besoin, l'agent vérifie les données autorisées, puis active l'alerte sur les datamarts validés.</p>\r\n        <div class=\"ia-demo-steps\">\r\n          <div class=\"ia-demo-step\">\r\n            <div class=\"ia-demo-num\">1</div>\r\n            <p><strong>L'utilisateur décrit son besoin</strong> en une phrase, comme il le dirait à un collègue.</p>\r\n          </div>\r\n          <div class=\"ia-demo-step\">\r\n            <div class=\"ia-demo-num\">2</div>\r\n            <p><strong>L'agent vérifie et confirme</strong> la requête sur les tables et indicateurs autorisés.</p>\r\n          </div>\r\n          <div class=\"ia-demo-step\">\r\n            <div class=\"ia-demo-num\">3</div>\r\n            <p><strong>L'alerte est active</strong> avec notification par email, Slack ou Teams dès que la condition est remplie.</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div class=\"ia-chat\">\r\n        <div class=\"ia-chat-header\">\r\n          <span class=\"dot\"></span>\r\n          Copilote Obstraken — connecté à vos datamarts\r\n        </div>\r\n        <div class=\"ia-chat-body\">\r\n          <div class=\"ia-chat-msg ia-chat-user\">\r\n            Préviens-moi si un client dépasse 60 jours de retard de paiement sur plus de 10&nbsp;000&nbsp;€\r\n          </div>\r\n          <div class=\"ia-chat-msg ia-chat-ai\">\r\n            <strong>Compris.</strong> Je surveille les créances clients supérieures à 10&nbsp;000&nbsp;€ avec un délai supérieur à 60 jours.<br><br>\r\n            Notification : <strong>email + Teams</strong><br>\r\n            Vérification : <strong>quotidienne à 8h</strong>\r\n            <span class=\"tag-ok\">Alerte créée</span>\r\n          </div>\r\n          <div class=\"ia-chat-msg ia-chat-user\">\r\n            Ajoute aussi une alerte si le pipeline commercial baisse de plus de 15% sur une semaine\r\n          </div>\r\n          <div class=\"ia-chat-msg ia-chat-ai\">\r\n            <strong>C'est fait.</strong> Je compare le pipeline total chaque lundi à S-1.<br><br>\r\n            Seuil : baisse &gt; 15%<br>\r\n            Destinataire : direction commerciale\r\n            <span class=\"tag-ok\">Alerte créée</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <div class=\"cta-band reveal\">\r\n      <p>Chaque palier peut être déployé en mode GCP France ou PREMI3NS souverain, selon vos contraintes.</p>\r\n      <a class=\"btn btn-primary\" href=\"/#contact\">Parler d'un cas d'usage IA<svg class=\"btn-arrow\" viewBox=\"0 0 28 16\" fill=\"none\" aria-hidden=\"true\"><path d=\"M0 8h22M16 2l6 6-6 6\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg></a>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<footer class=\"f\">\r\n  <div class=\"wrap frow2\">\r\n    <div class=\"brand\" style=\"gap:10px\"><img src=\"/favicon.svg\" alt=\"\" style=\"width:30px;height:30px;border-radius:8px\"/><span>© 2026 <b>OBSTRAKEN</b> — L'Usine de Données Souveraine as-a-Service</span></div>\r\n    <div class=\"legal\"><a href=\"/politique-confidentialite\">Politique de confidentialité</a><a href=\"/mentions-legales\">Mentions légales</a></div>\r\n  </div>\r\n</footer>"
};

